                }
            }
        }
    }
}

package com.antiprocrastinator.app.data.local

import android.content.Context
import android.content.SharedPreferences
import com.antiprocrastinator.app.data.model.*
import com.google.gson.Gson
import com.google.gson.reflect.TypeToken
import java.time.LocalDate

class PreferenceManager(context: Context) {
    private val prefs: SharedPreferences = context.getSharedPreferences("anti_procrastinator", Context.MODE_PRIVATE)
    private val gson = Gson()

    // ── To-Do Operations ──

    fun getTodos(): List<Todo> {
        val json = prefs.getString("todos", "[]") ?: "[]"
        return try {
            gson.fromJson(json, object : TypeToken<List<Todo>>() {}.type)
        } catch (e: Exception) { emptyList() }
    }

    fun saveTodos(todos: List<Todo>) {
        prefs.edit().putString("todos", gson.toJson(todos)).apply()
    }

    // ── Theme ──

    fun isDarkMode(): Boolean = prefs.getBoolean("dark_mode", false)
    fun setDarkMode(dark: Boolean) = prefs.edit().putBoolean("dark_mode", dark).apply()

    // ── Planer ──

    fun getPlanerMode(): PlanerMode? {
        val mode = prefs.getString("planer_mode", null) ?: return null
        return try { PlanerMode.valueOf(mode) } catch (e: Exception) { null }
    }

    fun setPlanerMode(mode: PlanerMode?) {
        prefs.edit().putString("planer_mode", mode?.name).apply()
    }

    fun getPlanerData(): List<PlanerPeriod> {
        val json = prefs.getString("planer_data", "[]") ?: "[]"
        return try {
            gson.fromJson(json, object : TypeToken<List<PlanerPeriod>>() {}.type)
        } catch (e: Exception) { emptyList() }
    }

    fun savePlanerData(data: List<PlanerPeriod>) {
        prefs.edit().putString("planer_data", gson.toJson(data)).apply()
    }

    // ── Weather Cache ──

    fun getCachedWeather(): WeatherData? {
        val json = prefs.getString("weather_cache", null) ?: return null
        val time = prefs.getLong("weather_cache_time", 0)
        if (System.currentTimeMillis() - time > 1800000) return null
        return try { gson.fromJson(json, WeatherData::class.java) } catch (e: Exception) { null }
    }

    fun cacheWeather(data: WeatherData) {
        prefs.edit()
            .putString("weather_cache", gson.toJson(data))
            .putLong("weather_cache_time", System.currentTimeMillis())
            .apply()
    }

    // ── Today Completed Count (für Haptik-Intensität) ──

    fun getTodayCompletedCount(): Int {
        val savedDate = prefs.getString("haptic_date", "")
        val today = LocalDate.now().toString()
        return if (savedDate == today) prefs.getInt("haptic_count", 0) else 0
    }

    fun incrementTodayCompleted() {
        val today = LocalDate.now().toString()
        val savedDate = prefs.getString("haptic_date", "")
        val count = if (savedDate == today) prefs.getInt("haptic_count", 0) else 0
        prefs.edit()
            .putString("haptic_date", today)
            .putInt("haptic_count", count + 1)
            .apply()
    }
}

package com.antiprocrastinator.app.data.model

import java.time.LocalDate
import java.time.LocalDateTime
import java.util.UUID

// ══════════════════════════════════════════════════════════
// To-Do Model
// ══════════════════════════════════════════════════════════

data class Todo(
    val id: String = UUID.randomUUID().toString(),
    val text: String,
    val date: LocalDate? = null,
    val category: TodoCategory = TodoCategory.ARBEIT,
    val completed: Boolean = false,
    val createdAt: LocalDateTime = LocalDateTime.now()
)

enum class TodoCategory(val label: String, val key: String) {
    ARBEIT("Arbeit", "arbeit"),
    PERSOENLICH("Persönlich", "persoenlich"),
    GESUNDHEIT("Gesundheit", "gesundheit"),
    LERNEN("Lernen", "lernen")
}

enum class TodoFilter { ALL, TODAY, OPEN, DONE }

data class TodoStats(
    val total: Int = 0,
    val done: Int = 0,
    val open: Int = 0,
    val rate: Int = 0,
    val todayCompleted: Int = 0
)

// ══════════════════════════════════════════════════════════
// Planer Models
// ══════════════════════════════════════════════════════════

enum class PlanerMode(val label: String, val periodLabel: String, val hasEcts: Boolean, val isSchule: Boolean) {
    SCHULE("Schulplaner", "Klasse", false, true),
    BACHELOR("Bachelor Studienplan", "Semester", true, false),
    MASTER("Master Studienplan", "Semester", true, false),
    PROVADIS("Studienplan Provadis", "Semester", true, false)
}

data class PlanerPeriod(
    val period: Int,
    val modules: MutableList<PlanerModule> = mutableListOf()
)

data class PlanerModule(
    val id: String = UUID.randomUUID().toString(),
    var name: String,
    var prof: String = "",
    var points: Int = 5,
    var pruefung: String = "",
    var isWab: Boolean = false,
    // Schul-Noten
    var noten: SchulNoten? = null,
    // Uni-Noten
    var grade: Double? = null,
    var status: ModuleStatus = ModuleStatus.OFFEN
)

data class SchulNoten(
    val schulaufgabe: MutableList<Int> = mutableListOf(),
    val ex: MutableList<Int> = mutableListOf(),
    val muendlich: MutableList<Int> = mutableListOf()
)

enum class ModuleStatus(val label: String) {
    OFFEN("Offen"),
    BESTANDEN("Bestanden"),
    NICHT_BESTANDEN("Nicht bestanden")
}

data class PlanerStats(
    val totalPoints: Int = 0,
    val completedPoints: Int = 0,
    val average: Double = 0.0,
    val gradedPoints: Int = 0
)

// ══════════════════════════════════════════════════════════
// Weather Model
// ══════════════════════════════════════════════════════════

data class WeatherData(
    val temp: Int = 0,
    val desc: String = "",
    val city: String = "",
    val dailyMax: List<Int> = emptyList(),
    val dailyMin: List<Int> = emptyList(),
    val dailyCodes: List<Int> = emptyList(),
    val dailyDates: List<String> = emptyList()
)

// ══════════════════════════════════════════════════════════
// Chart Data
// ══════════════════════════════════════════════════════════

data class ChartData(
    val labels: List<String>,
    val values: List<Int>
)

enum class ChartRange { WEEK, MONTH, YEAR }

// ══════════════════════════════════════════════════════════
// Daily Quotes
// ══════════════════════════════════════════════════════════

data class Quote(val text: String, val author: String)

object Quotes {
    val list = listOf(
        Quote("Der beste Zeitpunkt anzufangen war gestern. Der zweitbeste ist jetzt.", "Chinesisches Sprichwort"),
        Quote("Es ist nicht wenig Zeit, die wir haben, sondern viel Zeit, die wir nicht nutzen.", "Seneca"),
        Quote("Disziplin ist die Brücke zwischen Zielen und Ergebnissen.", "Jim Rohn"),
        Quote("Du musst nicht großartig sein, um anzufangen. Aber du musst anfangen, um großartig zu werden.", "Zig Ziglar"),
        Quote("Fokussiere dich nicht auf das Ergebnis. Fokussiere dich auf den Prozess.", "Nick Saban"),
        Quote("Der einzige Weg, großartige Arbeit zu leisten, ist zu lieben, was man tut.", "Steve Jobs"),
        Quote("Kleine Schritte sind besser als große Pläne.", "Unbekannt"),
        Quote("Perfektion ist der Feind des Fortschritts.", "Winston Churchill"),
        Quote("Erfolg ist die Summe kleiner Anstrengungen, Tag für Tag wiederholt.", "Robert Collier"),
        Quote("Motivation bringt dich in Gang. Gewohnheit bringt dich ans Ziel.", "Jim Ryun"),
        Quote("Handle, bevor du bereit bist.", "Mel Robbins"),
        Quote("Fortschritt, nicht Perfektion.", "Unbekannt"),
        Quote("Jeder Experte war einmal ein Anfänger.", "Helen Hayes"),
        Quote("Mach es jetzt. Manchmal wird aus Später Nie.", "Unbekannt"),
        Quote("Der Weg entsteht beim Gehen.", "Antonio Machado"),
    )

    fun daily(): Quote {
        val dayOfYear = java.time.LocalDate.now().dayOfYear
        return list[dayOfYear % list.size]
    }
}

package com.antiprocrastinator.app.data.repository

import com.antiprocrastinator.app.AntiProcrastinatorApp
import com.antiprocrastinator.app.data.local.PreferenceManager
import com.antiprocrastinator.app.data.model.*
import java.time.LocalDate
import java.time.format.DateTimeFormatter
import java.time.temporal.ChronoUnit

class TodoRepository {
    private val prefs: PreferenceManager = AntiProcrastinatorApp.instance.preferenceManager

    fun getAllTodos(): List<Todo> = prefs.getTodos()

    fun addTodo(text: String, date: LocalDate?, category: TodoCategory): Todo {
        val todos = prefs.getTodos().toMutableList()
        val todo = Todo(text = text, date = date, category = category)
        todos.add(todo)
        prefs.saveTodos(todos)
        return todo
    }

    fun toggleTodo(id: String): List<Todo> {
        val todos = prefs.getTodos().toMutableList()
        val idx = todos.indexOfFirst { it.id == id }
        if (idx >= 0) {
            val todo = todos[idx]
            todos[idx] = todo.copy(completed = !todo.completed)
            if (!todo.completed) { // war false, wird jetzt true → increment
                prefs.incrementTodayCompleted()
            }
        }
        prefs.saveTodos(todos)
        return todos
    }

    fun deleteTodo(id: String): List<Todo> {
        val todos = prefs.getTodos().filter { it.id != id }
        prefs.saveTodos(todos)
        return todos
    }

    fun getFilteredTodos(filter: TodoFilter, selectedDate: LocalDate? = null): List<Todo> {
        var list = prefs.getTodos()

        if (selectedDate != null) {
            list = list.filter { it.date == selectedDate }
        }

        list = when (filter) {
            TodoFilter.TODAY -> list.filter { it.date == LocalDate.now() }
            TodoFilter.OPEN -> list.filter { !it.completed }
            TodoFilter.DONE -> list.filter { it.completed }
            TodoFilter.ALL -> list
        }

        return list.sortedWith(compareBy<Todo> { it.completed }.thenByDescending { it.createdAt })
    }

    fun getStats(): TodoStats {
        val todos = prefs.getTodos()
        val total = todos.size
        val done = todos.count { it.completed }
        val open = total - done
        val rate = if (total > 0) (done * 100) / total else 0
        val todayCompleted = prefs.getTodayCompletedCount()
        return TodoStats(total, done, open, rate, todayCompleted)
    }

    fun getCategoryData(): Map<TodoCategory, Int> {
        val todos = prefs.getTodos()
        return TodoCategory.entries.associateWith { cat -> todos.count { it.category == cat } }
    }

    fun getChartData(range: ChartRange): ChartData {
        val todos = prefs.getTodos()
        val labels = mutableListOf<String>()
        val values = mutableListOf<Int>()
        val formatter = DateTimeFormatter.ofPattern("dd.MM")

        when (range) {
            ChartRange.WEEK -> {
                for (i in 6 downTo 0) {
                    val date = LocalDate.now().minusDays(i.toLong())
                    labels.add(date.dayOfWeek.name.take(2))
                    val dayTodos = todos.filter { it.date == date }
                    val completed = dayTodos.count { it.completed }
                    val total = dayTodos.size
                    values.add(if (total > 0) (completed * 100) / total else 0)
                }
            }
            ChartRange.MONTH -> {
                for (i in 29 downTo 0) {
                    val date = LocalDate.now().minusDays(i.toLong())
                    labels.add(date.format(formatter))
                    val dayTodos = todos.filter { it.date == date }
                    val completed = dayTodos.count { it.completed }
                    val total = dayTodos.size
                    values.add(if (total > 0) (completed * 100) / total else 0)
                }
            }
            ChartRange.YEAR -> {
                val months = listOf("Jan","Feb","Mär","Apr","Mai","Jun","Jul","Aug","Sep","Okt","Nov","Dez")
                for (i in 11 downTo 0) {
                    val date = LocalDate.now().minusMonths(i.toLong())
                    labels.add(months[date.monthValue - 1])
                    val monthTodos = todos.filter {
                        it.date != null && it.date.year == date.year && it.date.monthValue == date.monthValue
                    }
                    val completed = monthTodos.count { it.completed }
                    val total = monthTodos.size
                    values.add(if (total > 0) (completed * 100) / total else 0)
                }
            }
        }

        return ChartData(labels, values)
    }

    fun getTasksByDate(): Map<LocalDate, List<Todo>> {
        return prefs.getTodos().filter { it.date != null }.groupBy { it.date!! }
    }

    fun getTodayCompletedCount(): Int = prefs.getTodayCompletedCount()
}

package com.antiprocrastinator.app.navigation

import androidx.compose.animation.*
import androidx.compose.animation.core.*
import androidx.compose.foundation.background
import androidx.compose.foundation.gestures.*
import androidx.compose.foundation.layout.*
import androidx.compose.runtime.*
import androidx.compose.ui.Alignment
import androidx.compose.ui.Modifier
import androidx.compose.ui.draw.alpha
import androidx.compose.ui.input.pointer.pointerInput
import androidx.compose.ui.platform.LocalConfiguration
import androidx.compose.ui.platform.LocalDensity
import androidx.compose.ui.unit.IntOffset
import androidx.compose.ui.unit.dp
import androidx.lifecycle.viewmodel.compose.viewModel
import com.antiprocrastinator.app.ui.components.rememberHapticManager
import com.antiprocrastinator.app.ui.pages.*
import com.antiprocrastinator.app.ui.theme.AppTheme
import kotlinx.coroutines.launch
import kotlin.math.absoluteValue
import kotlin.math.roundToInt

/**
 * Snapchat-Style Cross-Navigation:
 *
 *              [Overview]    (oben – Uhr, Wetter, Planer)
 *                  ↑
 * [Summary] ← [To-Do] → [Calendar]
 *                  ↓
 *           [Visualizations]  (unten – Charts, Fortschritt)
 *
 * Horizontal: Summary ← ToDo → Calendar
 * Vertical: Overview ↑ ToDo ↓ Visualizations
 */
@Composable
fun SwipeNavigation() {
    val colors = AppTheme.colors

    // Current page: 0=Summary, 1=ToDo(center), 2=Calendar
    var horizontalPage by remember { mutableIntStateOf(1) }
    // Vertical offset from center: -1=Overview, 0=ToDo, 1=Visualizations
    var verticalPage by remember { mutableIntStateOf(0) }

    val coroutineScope = rememberCoroutineScope()
    val configuration = LocalConfiguration.current
    val screenWidthPx = with(LocalDensity.current) { configuration.screenWidthDp.dp.toPx() }
    val screenHeightPx = with(LocalDensity.current) { configuration.screenHeightDp.dp.toPx() }

    // Animated offsets
    val horizontalOffset = remember { Animatable(0f) }
    val verticalOffset = remember { Animatable(0f) }

    // Navigation state
    val isAtCenter = horizontalPage == 1 && verticalPage == 0

    // Page indicator dots
    val pageIndicatorAlpha by animateFloatAsState(
        targetValue = if (isAtCenter) 0.6f else 0f,
        animationSpec = tween(300), label = "indicator"
    )

    Box(
        modifier = Modifier
            .fillMaxSize()
            .background(colors.bg)
            .pointerInput(horizontalPage, verticalPage) {
                detectDragGestures(
                    onDragEnd = {
                        coroutineScope.launch {
                            val hOff = horizontalOffset.value
                            val vOff = verticalOffset.value

                            // Determine dominant axis
                            if (hOff.absoluteValue > vOff.absoluteValue) {
                                // Horizontal swipe
                                val threshold = screenWidthPx * 0.25f
                                when {
                                    hOff > threshold && horizontalPage > 0 -> {
                                        horizontalPage--
                                    }
                                    hOff < -threshold && horizontalPage < 2 -> {
                                        horizontalPage++
                                    }
                                }
                            } else {
                                // Vertical swipe (nur auf der Center-Page)
                                if (horizontalPage == 1) {
                                    val threshold = screenHeightPx * 0.2f
                                    when {
                                        vOff > threshold && verticalPage > -1 -> {
                                            verticalPage--
                                        }
                                        vOff < -threshold && verticalPage < 1 -> {
                                            verticalPage++
                                        }
                                    }
                                }
                            }
                            // Snap back
                            horizontalOffset.animateTo(0f, spring(stiffness = Spring.StiffnessLow))
                            verticalOffset.animateTo(0f, spring(stiffness = Spring.StiffnessLow))
                        }
                    },
                    onDrag = { change, dragAmount ->
                        change.consume()
                        coroutineScope.launch {
                            // Determine primary drag direction
                            if (dragAmount.x.absoluteValue > dragAmount.y.absoluteValue) {
                                // Horizontal - apply resistance at edges
                                val resistance = when {
                                    horizontalPage == 0 && dragAmount.x > 0 -> 0.3f
                                    horizontalPage == 2 && dragAmount.x < 0 -> 0.3f
                                    else -> 1f
                                }
                                horizontalOffset.snapTo(horizontalOffset.value + dragAmount.x * resistance)
                            } else if (horizontalPage == 1) {
                                // Vertical only on center page
                                val resistance = when {
                                    verticalPage == -1 && dragAmount.y > 0 -> 0.3f
                                    verticalPage == 1 && dragAmount.y < 0 -> 0.3f
                                    else -> 1f
                                }
                                verticalOffset.snapTo(verticalOffset.value + dragAmount.y * resistance)
                            }
                        }
                    }
                )
            }
    ) {
        // ── Background pages (pre-render for smooth transitions) ──

        // Calculate page offset for smooth transitions
        val hProgress = horizontalOffset.value / screenWidthPx
        val vProgress = verticalOffset.value / screenHeightPx

        // Render current page
        Box(
            modifier = Modifier
                .fillMaxSize()
                .offset { IntOffset(horizontalOffset.value.roundToInt(), verticalOffset.value.roundToInt()) }
        ) {
            when {
                horizontalPage == 0 -> SummaryPage()
                horizontalPage == 2 -> CalendarPage()
                verticalPage == -1 -> OverviewPage()
                verticalPage == 1 -> VisualizationsPage()
                else -> TodoPage()
            }
        }

        // Render peek of next pages (parallax effect)
        if (isAtCenter) {
            // Left peek (Summary)
            if (horizontalOffset.value > 0) {
                Box(
                    modifier = Modifier
                        .fillMaxSize()
                        .offset { IntOffset((-screenWidthPx + horizontalOffset.value).roundToInt(), 0) }
                        .alpha((horizontalOffset.value / screenWidthPx).coerceIn(0f, 1f) * 0.9f + 0.1f)
                ) {
                    SummaryPage()
                }
            }

            // Right peek (Calendar)
            if (horizontalOffset.value < 0) {
                Box(
                    modifier = Modifier
                        .fillMaxSize()
                        .offset { IntOffset((screenWidthPx + horizontalOffset.value).roundToInt(), 0) }
                        .alpha((-horizontalOffset.value / screenWidthPx).coerceIn(0f, 1f) * 0.9f + 0.1f)
                ) {
                    CalendarPage()
                }
            }

            // Top peek (Overview)
            if (verticalOffset.value > 0) {
                Box(
                    modifier = Modifier
                        .fillMaxSize()
                        .offset { IntOffset(0, (-screenHeightPx + verticalOffset.value).roundToInt()) }
                        .alpha((verticalOffset.value / screenHeightPx).coerceIn(0f, 1f) * 0.9f + 0.1f)
                ) {
                    OverviewPage()
                }
            }

            // Bottom peek (Visualizations)
            if (verticalOffset.value < 0) {
                Box(
                    modifier = Modifier
                        .fillMaxSize()
                        .offset { IntOffset(0, (screenHeightPx + verticalOffset.value).roundToInt()) }
                        .alpha((-verticalOffset.value / screenHeightPx).coerceIn(0f, 1f) * 0.9f + 0.1f)
                ) {
                    VisualizationsPage()
                }
            }
        }

        // ── Page Indicator Dots ──
        if (pageIndicatorAlpha > 0.01f) {
            // Horizontal indicator (bottom center)
            Row(
                modifier = Modifier
                    .align(Alignment.BottomCenter)
                    .padding(bottom = 40.dp)
                    .alpha(pageIndicatorAlpha),
                horizontalArrangement = Arrangement.spacedBy(8.dp)
            ) {
                for (i in 0..2) {
                    Box(
                        modifier = Modifier
                            .size(if (i == horizontalPage) 8.dp else 5.dp)
                            .background(
                                color = if (i == horizontalPage) colors.text else colors.textMuted,
                                shape = androidx.compose.foundation.shape.CircleShape
                            )
                    )
                }
            }

            // Vertical indicator (right center)
            Column(
                modifier = Modifier
                    .align(Alignment.CenterEnd)
                    .padding(end = 12.dp)
                    .alpha(pageIndicatorAlpha),
                verticalArrangement = Arrangement.spacedBy(8.dp)
            ) {
                for (i in -1..1) {
                    Box(
                        modifier = Modifier
                            .size(if (i == verticalPage) 8.dp else 5.dp)
                            .background(
                                color = if (i == verticalPage) colors.text else colors.textMuted,
                                shape = androidx.compose.foundation.shape.CircleShape
                            )
                    )
                }
            }
        }
    }
}

package com.antiprocrastinator.app.ui.components

import android.content.Context
import android.os.Build
import android.os.VibrationEffect
import android.os.Vibrator
import android.os.VibratorManager
import androidx.compose.runtime.Composable
import androidx.compose.runtime.remember
import androidx.compose.ui.platform.LocalContext

/**
 * HapticManager — Haptisches Feedback beim Abhaken von To-Dos.
 * Je mehr To-Dos pro Tag abgehakt werden, desto stärker die Vibration.
 *
 * Stufe 1 (1-2 Tasks):   Leichtes Tick
 * Stufe 2 (3-5 Tasks):   Mittleres Feedback
 * Stufe 3 (6-9 Tasks):   Starkes Feedback
 * Stufe 4 (10+ Tasks):   Doppel-Burst – Belohnungsgefühl!
 */
class HapticManager(private val context: Context) {

    private val vibrator: Vibrator by lazy {
        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.S) {
            val manager = context.getSystemService(Context.VIBRATOR_MANAGER_SERVICE) as VibratorManager
            manager.defaultVibrator
        } else {
            @Suppress("DEPRECATION")
            context.getSystemService(Context.VIBRATOR_SERVICE) as Vibrator
        }
    }

    fun todoChecked(todayCount: Int) {
        if (!vibrator.hasVibrator()) return

        when {
            todayCount <= 2 -> lightTick()
            todayCount <= 5 -> mediumImpact()
            todayCount <= 9 -> heavyImpact()
            else -> celebrationBurst()
        }
    }

    private fun lightTick() {
        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.Q) {
            vibrator.vibrate(VibrationEffect.createPredefined(VibrationEffect.EFFECT_TICK))
        } else {
            vibrator.vibrate(VibrationEffect.createOneShot(30, 40))
        }
    }

    private fun mediumImpact() {
        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.Q) {
            vibrator.vibrate(VibrationEffect.createPredefined(VibrationEffect.EFFECT_CLICK))
        } else {
            vibrator.vibrate(VibrationEffect.createOneShot(50, 120))
        }
    }

    private fun heavyImpact() {
        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.Q) {
            vibrator.vibrate(VibrationEffect.createPredefined(VibrationEffect.EFFECT_HEAVY_CLICK))
        } else {
            vibrator.vibrate(VibrationEffect.createOneShot(80, 200))
        }
    }

    private fun celebrationBurst() {
        // Doppel-Burst Pattern: vibrate-pause-vibrate-pause-vibrate
        val timings = longArrayOf(0, 60, 60, 80, 60, 120)
        val amplitudes = intArrayOf(0, 180, 0, 220, 0, 255)
        vibrator.vibrate(VibrationEffect.createWaveform(timings, amplitudes, -1))
    }
}

@Composable
fun rememberHapticManager(): HapticManager {
    val context = LocalContext.current
    return remember { HapticManager(context) }
}

