// Weather Card
// ══════════════════════════════════════════════════════════

@Composable
private fun WeatherCard(weather: WeatherData) {
    val colors = AppTheme.colors

    Box(
        modifier = Modifier
            .fillMaxWidth()
            .background(colors.card, RoundedCornerShape(16.dp))
            .border(1.dp, colors.border, RoundedCornerShape(16.dp))
            .padding(16.dp)
    ) {
        Row(
            modifier = Modifier.fillMaxWidth(),
            horizontalArrangement = Arrangement.SpaceBetween,
            verticalAlignment = Alignment.CenterVertically
        ) {
            Column {
                Text(
                    "${weather.temp}°",
                    fontFamily = SpaceMono,
                    fontSize = 40.sp,
                    fontWeight = FontWeight.Light,
                    color = colors.text
                )
                Text(weather.desc, fontSize = 11.sp, color = colors.textMuted, fontFamily = SpaceMono)
            }
            Column(horizontalAlignment = Alignment.End) {
                Text(weather.city, fontSize = 13.sp, fontWeight = FontWeight.SemiBold, color = colors.text)
                if (weather.dailyMax.isNotEmpty()) {
                    Text(
                        "H:${weather.dailyMax[0]}° L:${weather.dailyMin[0]}°",
                        fontFamily = SpaceMono, fontSize = 10.sp, color = colors.textMuted
                    )
                }
            }
        }
    }
}

// ══════════════════════════════════════════════════════════
// Planer Mode Select
// ══════════════════════════════════════════════════════════

@Composable
private fun PlanerModeSelect(onSelect: (PlanerMode) -> Unit) {
    val colors = AppTheme.colors

    Column {
        Text(
            "PLANER",
            fontFamily = SpaceMono,
            fontSize = 9.sp,
            fontWeight = FontWeight.Bold,
            color = colors.textMuted,
            letterSpacing = 3.sp,
            modifier = Modifier.padding(bottom = 12.dp)
        )

        Text(
            "Wähle deinen Planer",
            fontFamily = SpaceMono,
            fontSize = 10.sp,
            color = colors.textMuted,
            letterSpacing = 2.sp,
            modifier = Modifier.padding(bottom = 16.dp)
        )

        val modes = listOf(
            PlanerMode.SCHULE to ".:S:." to "Klassen 5-13",
            PlanerMode.BACHELOR to ".:B:." to "6 Semester · 180 ECTS",
            PlanerMode.MASTER to ".:M:." to "4 Semester · 120 ECTS",
            PlanerMode.PROVADIS to ".:P:." to "Informatik B.Sc."
        )

        Column(verticalArrangement = Arrangement.spacedBy(10.dp)) {
            modes.chunked(2).forEach { row ->
                Row(
                    modifier = Modifier.fillMaxWidth(),
                    horizontalArrangement = Arrangement.spacedBy(10.dp)
                ) {
                    row.forEach { (modeIcon, desc) ->
                        val (mode, icon) = modeIcon
                        Box(
                            modifier = Modifier
                                .weight(1f)
                                .clip(RoundedCornerShape(16.dp))
                                .background(colors.card)
                                .border(1.5.dp, colors.border, RoundedCornerShape(16.dp))
                                .clickable { onSelect(mode) }
                                .padding(20.dp),
                            contentAlignment = Alignment.Center
                        ) {
                            Column(horizontalAlignment = Alignment.CenterHorizontally) {
                                Box(
                                    modifier = Modifier
                                        .size(48.dp)
                                        .border(1.5.dp, colors.border, RoundedCornerShape(12.dp)),
                                    contentAlignment = Alignment.Center
                                ) {
                                    Text(icon, fontFamily = SpaceMono, fontSize = 12.sp, fontWeight = FontWeight.Bold, color = colors.text)
                                }
                                Spacer(Modifier.height(8.dp))
                                Text(
                                    mode.label.substringBefore(" ").uppercase(),
                                    fontFamily = SpaceMono,
                                    fontSize = 11.sp,
                                    fontWeight = FontWeight.Bold,
                                    color = colors.text,
                                    letterSpacing = 1.sp
                                )
                                Text(desc, fontSize = 9.sp, color = colors.textMuted, textAlign = TextAlign.Center)
                            }
                        }
                    }
                }
            }
        }
    }
}

// ══════════════════════════════════════════════════════════
// Planer Quick View
// ══════════════════════════════════════════════════════════

@Composable
private fun PlanerQuickView(mode: PlanerMode, data: List<PlanerPeriod>, onReset: () -> Unit) {
    val colors = AppTheme.colors

    Box(
        modifier = Modifier
            .fillMaxWidth()
            .background(colors.card, RoundedCornerShape(16.dp))
            .border(1.dp, colors.border, RoundedCornerShape(16.dp))
            .padding(16.dp)
    ) {
        Column {
            Row(
                modifier = Modifier.fillMaxWidth(),
                horizontalArrangement = Arrangement.SpaceBetween,
                verticalAlignment = Alignment.CenterVertically
            ) {
                Text(
                    mode.label.uppercase(),
                    fontFamily = SpaceMono,
                    fontSize = 10.sp,
                    fontWeight = FontWeight.Bold,
                    color = colors.textMuted,
                    letterSpacing = 2.sp
                )
                Box(
                    modifier = Modifier
                        .clip(RoundedCornerShape(8.dp))
                        .border(1.dp, colors.border, RoundedCornerShape(8.dp))
                        .clickable(onClick = onReset)
                        .padding(horizontal = 10.dp, vertical = 4.dp)
                ) {
                    Text("⟳", fontFamily = SpaceMono, fontSize = 12.sp, color = colors.textMuted)
                }
            }

            Spacer(Modifier.height(12.dp))

            if (data.isEmpty()) {
                Text("Noch keine Daten", color = colors.textMuted, fontSize = 11.sp, fontFamily = SpaceMono)
            } else {
                data.forEach { period ->
                    Text(
                        "${mode.periodLabel} ${period.period} — ${period.modules.size} ${if (mode.isSchule) "Fächer" else "Module"}",
                        fontFamily = SpaceMono,
                        fontSize = 11.sp,
                        color = colors.text,
                        modifier = Modifier.padding(vertical = 3.dp)
                    )
                }
            }
        }
    }
}

package com.antiprocrastinator.app.ui.pages

import androidx.compose.animation.core.*
import androidx.compose.foundation.*
import androidx.compose.foundation.layout.*
import androidx.compose.foundation.shape.CircleShape
import androidx.compose.foundation.shape.RoundedCornerShape
import androidx.compose.material3.*
import androidx.compose.runtime.*
import androidx.compose.ui.Alignment
import androidx.compose.ui.Modifier
import androidx.compose.ui.draw.clip
import androidx.compose.ui.graphics.drawscope.Stroke
import androidx.compose.ui.text.font.FontWeight
import androidx.compose.ui.text.style.TextOverflow
import androidx.compose.ui.unit.dp
import androidx.compose.ui.unit.sp
import com.antiprocrastinator.app.AntiProcrastinatorApp
import com.antiprocrastinator.app.data.model.*
import com.antiprocrastinator.app.data.repository.TodoRepository
import com.antiprocrastinator.app.ui.theme.*
import kotlinx.coroutines.delay
import java.time.LocalDate
import java.time.LocalTime
import java.time.YearMonth
import java.time.ZoneId
import java.time.format.DateTimeFormatter
import java.util.*

/**
 * Summary Page — Links (Swipe nach rechts von ToDo)
 * Alle wichtigsten Infos auf einen Blick (kompakte Version):
 * Fortschrittsanzeige, Kalender-Mini, heutige ToDos, Uhr, Wetter, Noten
 */
@Composable
fun SummaryPage() {
    val colors = AppTheme.colors
    val repository = remember { TodoRepository() }
    val prefs = AntiProcrastinatorApp.instance.preferenceManager
    val stats = remember { repository.getStats() }
    val todayTodos = remember { repository.getFilteredTodos(TodoFilter.TODAY) }
    val weather = remember { prefs.getCachedWeather() }
    val categoryData = remember { repository.getCategoryData() }

    var time by remember { mutableStateOf(LocalTime.now(ZoneId.of("Europe/Berlin"))) }

    LaunchedEffect(Unit) {
        while (true) {
            time = LocalTime.now(ZoneId.of("Europe/Berlin"))
            delay(1000)
        }
    }

    Column(
        modifier = Modifier
            .fillMaxSize()
            .background(colors.bg)
            .statusBarsPadding()
            .verticalScroll(rememberScrollState())
            .padding(horizontal = 16.dp)
    ) {
        Spacer(Modifier.height(16.dp))

        Text(
            "DASHBOARD",
            style = MaterialTheme.typography.labelLarge,
            color = colors.textMuted,
            letterSpacing = 3.sp
        )

        Spacer(Modifier.height(16.dp))

        // ── Row 1: Uhr + Wetter ──
        Row(
            modifier = Modifier.fillMaxWidth(),
            horizontalArrangement = Arrangement.spacedBy(10.dp)
        ) {
            // Mini Clock
            Box(
                modifier = Modifier
                    .weight(1f)
                    .background(colors.card, RoundedCornerShape(16.dp))
                    .border(1.dp, colors.border, RoundedCornerShape(16.dp))
                    .padding(16.dp),
                contentAlignment = Alignment.Center
            ) {
                Column(horizontalAlignment = Alignment.CenterHorizontally) {
                    Text(
                        "UHR",
                        fontFamily = SpaceMono,
                        fontSize = 8.sp,
                        fontWeight = FontWeight.Bold,
                        color = colors.textMuted,
                        letterSpacing = 2.sp
                    )
                    Spacer(Modifier.height(4.dp))
                    Text(
                        time.format(DateTimeFormatter.ofPattern("HH:mm")),
                        fontFamily = SpaceMono,
                        fontSize = 28.sp,
                        fontWeight = FontWeight.Light,
                        color = colors.text,
                        letterSpacing = 2.sp
                    )
                    Text(
                        LocalDate.now().format(DateTimeFormatter.ofPattern("dd. MMM", Locale.GERMAN)).uppercase(),
                        fontFamily = SpaceMono,
                        fontSize = 9.sp,
                        color = colors.textMuted
                    )
                }
            }

            // Mini Weather
            Box(
                modifier = Modifier
                    .weight(1f)
                    .background(colors.card, RoundedCornerShape(16.dp))
                    .border(1.dp, colors.border, RoundedCornerShape(16.dp))
                    .padding(16.dp),
                contentAlignment = Alignment.Center
            ) {
                Column(horizontalAlignment = Alignment.CenterHorizontally) {
                    Text(
                        "WETTER",
                        fontFamily = SpaceMono,
                        fontSize = 8.sp,
                        fontWeight = FontWeight.Bold,
                        color = colors.textMuted,
                        letterSpacing = 2.sp
                    )
                    Spacer(Modifier.height(4.dp))
                    Text(
                        "${weather?.temp ?: "--"}°",
                        fontFamily = SpaceMono,
                        fontSize = 28.sp,
                        fontWeight = FontWeight.Light,
                        color = colors.text
                    )
                    Text(
                        weather?.city ?: "—",
                        fontFamily = SpaceMono,
                        fontSize = 9.sp,
                        color = colors.textMuted,
                        maxLines = 1,
                        overflow = TextOverflow.Ellipsis
                    )
                }
            }
        }

        Spacer(Modifier.height(10.dp))

        // ── Row 2: Progress Ring + Stats ──
        Row(
            modifier = Modifier.fillMaxWidth(),
            horizontalArrangement = Arrangement.spacedBy(10.dp)
        ) {
            // Progress Ring
            Box(
                modifier = Modifier
                    .weight(1f)
                    .background(colors.card, RoundedCornerShape(16.dp))
                    .border(1.dp, colors.border, RoundedCornerShape(16.dp))
                    .padding(16.dp),
                contentAlignment = Alignment.Center
            ) {
                Column(horizontalAlignment = Alignment.CenterHorizontally) {
                    Text("FORTSCHRITT", fontFamily = SpaceMono, fontSize = 8.sp, fontWeight = FontWeight.Bold, color = colors.textMuted, letterSpacing = 2.sp)
                    Spacer(Modifier.height(8.dp))
                    Box(contentAlignment = Alignment.Center) {
                        CircularProgressIndicator(
                            progress = { if (stats.total > 0) stats.done.toFloat() / stats.total else 0f },
                            modifier = Modifier.size(60.dp),
                            color = colors.text,
                            trackColor = colors.border,
                            strokeWidth = 4.dp
                        )
                        Text(
                            "${stats.rate}%",
                            fontFamily = SpaceMono,
                            fontSize = 14.sp,
                            fontWeight = FontWeight.Bold,
                            color = colors.text
                        )
                    }
                    Spacer(Modifier.height(4.dp))
                    Text(
                        "${stats.done}/${stats.total}",
                        fontFamily = SpaceMono,
                        fontSize = 10.sp,
                        color = colors.textMuted
                    )
                }
            }

            // Stats
            Column(
                modifier = Modifier.weight(1f),
                verticalArrangement = Arrangement.spacedBy(10.dp)
            ) {
                Row(horizontalArrangement = Arrangement.spacedBy(10.dp)) {
                    MiniStat("OFFEN", "${stats.open}", Modifier.weight(1f))
                    MiniStat("ERLEDIGT", "${stats.done}", Modifier.weight(1f))
                }
                Row(horizontalArrangement = Arrangement.spacedBy(10.dp)) {
                    MiniStat("GESAMT", "${stats.total}", Modifier.weight(1f))
                    MiniStat("RATE", "${stats.rate}%", Modifier.weight(1f))
                }
            }
        }

        Spacer(Modifier.height(10.dp))

        // ── Mini Calendar (current month overview) ──
        Box(
            modifier = Modifier
                .fillMaxWidth()
                .background(colors.card, RoundedCornerShape(16.dp))
                .border(1.dp, colors.border, RoundedCornerShape(16.dp))
                .padding(12.dp)
        ) {
            Column {
                Text("KALENDER", fontFamily = SpaceMono, fontSize = 8.sp, fontWeight = FontWeight.Bold, color = colors.textMuted, letterSpacing = 2.sp)
                Spacer(Modifier.height(8.dp))

                val today = LocalDate.now()
                val month = YearMonth.now()

                Row(modifier = Modifier.fillMaxWidth()) {
                    listOf("M", "D", "M", "D", "F", "S", "S").forEach { d ->
                        Text(
                            d,
                            modifier = Modifier.weight(1f),
                            textAlign = androidx.compose.ui.text.style.TextAlign.Center,
                            fontFamily = SpaceMono,
                            fontSize = 7.sp,
                            color = colors.textMuted,
                            fontWeight = FontWeight.Bold
                        )
                    }
                }
                Spacer(Modifier.height(4.dp))

                var dayOffset = month.atDay(1).dayOfWeek.value - 1
                var dayNum = 1
                val totalDays = month.lengthOfMonth()

                for (week in 0..5) {
                    if (dayNum > totalDays) break
                    Row(modifier = Modifier.fillMaxWidth()) {
                        for (dow in 0..6) {
                            if ((week == 0 && dow < dayOffset) || dayNum > totalDays) {
                                Spacer(Modifier.weight(1f))
                            } else {
                                val d = dayNum
                                val isToday = month.atDay(d) == today
                                Box(
                                    modifier = Modifier
                                        .weight(1f)
                                        .padding(1.dp)
                                        .aspectRatio(1f)
                                        .clip(RoundedCornerShape(4.dp))
                                        .background(
                                            if (isToday) colors.text else colors.bg
                                        ),
                                    contentAlignment = Alignment.Center
                                ) {
                                    Text(
                                        "$d",
                                        fontFamily = SpaceMono,
                                        fontSize = 7.sp,
                                        color = if (isToday) colors.bg else colors.textMuted,
                                        fontWeight = if (isToday) FontWeight.Bold else FontWeight.Normal
                                    )
                                }
                                dayNum++
                            }
                        }
                    }
                }
            }
        }

        Spacer(Modifier.height(10.dp))

        // ── Today's Todos ──
        Box(
            modifier = Modifier
                .fillMaxWidth()
                .background(colors.card, RoundedCornerShape(16.dp))
                .border(1.dp, colors.border, RoundedCornerShape(16.dp))
                .padding(12.dp)
        ) {
            Column {
                Text("HEUTE", fontFamily = SpaceMono, fontSize = 8.sp, fontWeight = FontWeight.Bold, color = colors.textMuted, letterSpacing = 2.sp)
                Spacer(Modifier.height(6.dp))

                if (todayTodos.isEmpty()) {
                    Text("Keine Aufgaben für heute", fontFamily = SpaceMono, fontSize = 10.sp, color = colors.textMuted)
                } else {
                    todayTodos.take(5).forEach { todo ->
                        Row(
                            modifier = Modifier.padding(vertical = 2.dp),
                            verticalAlignment = Alignment.CenterVertically
                        ) {
                            Box(
                                modifier = Modifier
                                    .size(10.dp)
                                    .clip(CircleShape)
                                    .background(if (todo.completed) colors.text else colors.border)
                                    .then(
                                        if (!todo.completed) Modifier.border(1.dp, colors.textMuted, CircleShape)
                                        else Modifier
                                    )
                            )
                            Spacer(Modifier.width(8.dp))
                            Text(
                                todo.text,
                                fontSize = 10.sp,
                                color = if (todo.completed) colors.textMuted else colors.text,
                                maxLines = 1,
                                overflow = TextOverflow.Ellipsis
                            )
                        }
                    }
                    if (todayTodos.size > 5) {
                        Text("+${todayTodos.size - 5} mehr", fontFamily = SpaceMono, fontSize = 8.sp, color = colors.textMuted, modifier = Modifier.padding(top = 2.dp))
                    }
                }
            }
        }

        Spacer(Modifier.height(10.dp))

        // ── Mini Category Bars ──
        Box(
            modifier = Modifier
                .fillMaxWidth()
                .background(colors.card, RoundedCornerShape(16.dp))
                .border(1.dp, colors.border, RoundedCornerShape(16.dp))
                .padding(12.dp)
        ) {
            Column {
                Text("KATEGORIEN", fontFamily = SpaceMono, fontSize = 8.sp, fontWeight = FontWeight.Bold, color = colors.textMuted, letterSpacing = 2.sp)
                Spacer(Modifier.height(8.dp))
                val total = categoryData.values.sum().coerceAtLeast(1)
                categoryData.forEach { (cat, count) ->
                    Row(
                        modifier = Modifier
                            .fillMaxWidth()
                            .padding(vertical = 2.dp),
                        verticalAlignment = Alignment.CenterVertically
                    ) {
                        Text(
                            cat.label.take(4).uppercase(),
                            fontFamily = SpaceMono,
                            fontSize = 7.sp,
                            fontWeight = FontWeight.Bold,
                            color = colors.textMuted,
                            modifier = Modifier.width(40.dp)
                        )
                        Box(
                            modifier = Modifier
                                .weight(1f)
                                .height(6.dp)
                                .background(colors.input, RoundedCornerShape(3.dp))
                        ) {
                            Box(
                                modifier = Modifier
                                    .fillMaxHeight()
                                    .fillMaxWidth(count.toFloat() / total)
                                    .background(colors.text.copy(alpha = 0.6f), RoundedCornerShape(3.dp))
                            )
                        }
                        Spacer(Modifier.width(6.dp))
                        Text("$count", fontFamily = SpaceMono, fontSize = 8.sp, fontWeight = FontWeight.Bold, color = colors.text)
                    }
                }
            }
        }

        Spacer(Modifier.height(40.dp))
    }
}

@Composable
private fun MiniStat(label: String, value: String, modifier: Modifier = Modifier) {
    val colors = AppTheme.colors
    Box(
        modifier = modifier
            .background(colors.card, RoundedCornerShape(12.dp))
            .border(1.dp, colors.border, RoundedCornerShape(12.dp))
            .padding(10.dp),
        contentAlignment = Alignment.Center
    ) {
        Column(horizontalAlignment = Alignment.CenterHorizontally) {
            Text(value, fontFamily = SpaceMono, fontSize = 14.sp, fontWeight = FontWeight.Bold, color = colors.text)
            Text(label, fontFamily = SpaceMono, fontSize = 6.sp, fontWeight = FontWeight.Bold, color = colors.textMuted, letterSpacing = 1.sp)
        }
    }
}

package com.antiprocrastinator.app.ui.pages

import androidx.compose.animation.*
import androidx.compose.animation.core.*
import androidx.compose.foundation.*
import androidx.compose.foundation.layout.*
import androidx.compose.foundation.lazy.LazyColumn
import androidx.compose.foundation.lazy.items
import androidx.compose.foundation.shape.CircleShape
import androidx.compose.foundation.shape.RoundedCornerShape
import androidx.compose.foundation.text.BasicTextField
import androidx.compose.material3.*
import androidx.compose.runtime.*
import androidx.compose.ui.Alignment
import androidx.compose.ui.Modifier
import androidx.compose.ui.draw.clip
import androidx.compose.ui.graphics.SolidColor
import androidx.compose.ui.text.font.FontWeight
import androidx.compose.ui.text.style.TextDecoration
import androidx.compose.ui.text.style.TextOverflow
import androidx.compose.ui.unit.dp
import androidx.compose.ui.unit.sp
import com.antiprocrastinator.app.data.model.*
import com.antiprocrastinator.app.data.repository.TodoRepository
import com.antiprocrastinator.app.ui.components.rememberHapticManager
import com.antiprocrastinator.app.ui.theme.AppTheme
import com.antiprocrastinator.app.ui.theme.SpaceMono
import java.time.LocalDate
import java.time.format.DateTimeFormatter

/**
 * To-Do Page — Hauptseite (Fullscreen)
 * Snapchat-Centerpage: Minimalistisch, touch-optimiert
 */
@Composable
fun TodoPage() {
    val colors = AppTheme.colors
    val repository = remember { TodoRepository() }
    val haptic = rememberHapticManager()

    var todos by remember { mutableStateOf(repository.getAllTodos()) }
    var filter by remember { mutableStateOf(TodoFilter.ALL) }
    var inputText by remember { mutableStateOf("") }
    var selectedCategory by remember { mutableStateOf(TodoCategory.ARBEIT) }
    var showCategoryPicker by remember { mutableStateOf(false) }
    val stats = remember(todos) { repository.getStats() }

    fun refresh() { todos = repository.getFilteredTodos(filter) }

    Column(
        modifier = Modifier
            .fillMaxSize()
            .background(colors.bg)
            .statusBarsPadding()
            .padding(horizontal = 20.dp)
    ) {
        Spacer(Modifier.height(16.dp))

        // ── Header ──
        Row(
            modifier = Modifier.fillMaxWidth(),
            horizontalArrangement = Arrangement.SpaceBetween,
            verticalAlignment = Alignment.CenterVertically
        ) {
            Column {
                Text(
                    "AUFGABEN",
                    style = MaterialTheme.typography.labelLarge,
                    color = colors.textMuted,
                    letterSpacing = 3.sp
                )
                Text(
                    "${stats.done}/${stats.total} erledigt",
                    style = MaterialTheme.typography.bodySmall,
                    color = colors.textMuted
                )
            }

            // Tages-Fortschrittsring
            Box(contentAlignment = Alignment.Center) {
                CircularProgressIndicator(
                    progress = { if (stats.total > 0) stats.done.toFloat() / stats.total else 0f },
                    modifier = Modifier.size(44.dp),
                    color = colors.text,
                    trackColor = colors.border,
                    strokeWidth = 3.dp
                )
                Text(
                    "${stats.rate}%",
                    fontFamily = SpaceMono,
                    fontSize = 10.sp,
                    fontWeight = FontWeight.Bold,
                    color = colors.text
                )
            }
        }

        Spacer(Modifier.height(20.dp))

        // ── Input Row ──
        Row(
            modifier = Modifier
                .fillMaxWidth()
                .background(colors.card, RoundedCornerShape(16.dp))
                .border(1.dp, colors.border, RoundedCornerShape(16.dp))
                .padding(4.dp),
            verticalAlignment = Alignment.CenterVertically
        ) {
            // Category Pill
            Box(
                modifier = Modifier
                    .clip(RoundedCornerShape(12.dp))
                    .background(colors.input)
                    .clickable { showCategoryPicker = !showCategoryPicker }
                    .padding(horizontal = 12.dp, vertical = 12.dp)
            ) {
                Text(
                    selectedCategory.label.take(3).uppercase(),
                    fontFamily = SpaceMono,
                    fontSize = 8.sp,
                    fontWeight = FontWeight.Bold,
                    color = colors.textSecondary,
                    letterSpacing = 1.sp
                )
            }

            BasicTextField(
                value = inputText,
                onValueChange = { inputText = it },
                modifier = Modifier
                    .weight(1f)
                    .padding(horizontal = 12.dp, vertical = 12.dp),
                textStyle = MaterialTheme.typography.bodyMedium.copy(color = colors.text),
                cursorBrush = SolidColor(colors.text),
                singleLine = true,
                decorationBox = { innerTextField ->
                    Box {
                        if (inputText.isEmpty()) {
                            Text(
                                "Neue Aufgabe...",
                                style = MaterialTheme.typography.bodyMedium,
                                color = colors.textMuted
                            )
                        }
                        innerTextField()
                    }
                }
            )

            // Add Button
            Box(
                modifier = Modifier
                    .size(40.dp)
                    .clip(RoundedCornerShape(12.dp))
                    .background(colors.text)
                    .clickable {
                        if (inputText.isNotBlank()) {
                            repository.addTodo(inputText.trim(), LocalDate.now(), selectedCategory)
                            inputText = ""
                            refresh()
                        }
                    },
                contentAlignment = Alignment.Center
            ) {
                Text("+", color = colors.bg, fontSize = 20.sp, fontWeight = FontWeight.Light)
            }
        }

        // ── Category Picker (animated) ──
        AnimatedVisibility(
            visible = showCategoryPicker,
            enter = expandVertically() + fadeIn(),
            exit = shrinkVertically() + fadeOut()
        ) {
            Row(
                modifier = Modifier
                    .fillMaxWidth()
                    .padding(top = 8.dp),
                horizontalArrangement = Arrangement.spacedBy(6.dp)
            ) {
                TodoCategory.entries.forEach { cat ->
                    val isSelected = cat == selectedCategory
                    Box(
                        modifier = Modifier
                            .clip(RoundedCornerShape(20.dp))
                            .background(if (isSelected) colors.text else colors.input)
                            .border(1.dp, if (isSelected) colors.text else colors.border, RoundedCornerShape(20.dp))
                            .clickable {
                                selectedCategory = cat
                                showCategoryPicker = false
                            }
                            .padding(horizontal = 14.dp, vertical = 8.dp)
                    ) {
                        Text(
                            cat.label,
                            fontFamily = SpaceMono,
                            fontSize = 9.sp,
                            fontWeight = FontWeight.SemiBold,
                            color = if (isSelected) colors.bg else colors.textSecondary,
                            letterSpacing = 1.sp
                        )
                    }
                }
            }
        }

        Spacer(Modifier.height(12.dp))

        // ── Filter Pills ──
        Row(
            horizontalArrangement = Arrangement.spacedBy(6.dp)
        ) {
            TodoFilter.entries.forEach { f ->
                val label = when (f) {
                    TodoFilter.ALL -> "Alle"
                    TodoFilter.TODAY -> "Heute"
                    TodoFilter.OPEN -> "Offen"
                    TodoFilter.DONE -> "Erledigt"
                }
                val isActive = f == filter
                Box(
                    modifier = Modifier
                        .clip(RoundedCornerShape(20.dp))
                        .background(if (isActive) colors.text else colors.bg)
                        .border(1.dp, if (isActive) colors.text else colors.border, RoundedCornerShape(20.dp))
                        .clickable {
                            filter = f
                            refresh()
                        }
                        .padding(horizontal = 14.dp, vertical = 7.dp)
                ) {
                    Text(
                        label.uppercase(),
                        fontFamily = SpaceMono,
                        fontSize = 9.sp,
                        fontWeight = FontWeight.Bold,
                        color = if (isActive) colors.bg else colors.textMuted,
                        letterSpacing = 1.sp
                    )
                }
            }
        }

        Spacer(Modifier.height(12.dp))

        // ── Todo List ──
        if (todos.isEmpty()) {
            Box(
                modifier = Modifier.fillMaxSize(),
                contentAlignment = Alignment.Center
            ) {
                Column(horizontalAlignment = Alignment.CenterHorizontally) {
                    Text("--", color = colors.textMuted, fontFamily = SpaceMono, fontSize = 20.sp)
                    Spacer(Modifier.height(8.dp))
                    Text(
                        "KEINE AUFGABEN",
                        fontFamily = SpaceMono,
                        fontSize = 10.sp,
                        color = colors.textMuted,
                        letterSpacing = 2.sp
                    )
                }
            }
        } else {
            LazyColumn(
                verticalArrangement = Arrangement.spacedBy(2.dp)
            ) {
                items(todos, key = { it.id }) { todo ->
                    TodoItem(
                        todo = todo,
                        onToggle = {
                            repository.toggleTodo(todo.id)
                            val count = repository.getTodayCompletedCount()
                            if (!todo.completed) haptic.todoChecked(count)
                            refresh()
                        },
                        onDelete = {
                            repository.deleteTodo(todo.id)
                            refresh()
                        }
                    )
                }
            }
        }
    }
}

@Composable
private fun TodoItem(
    todo: Todo,
    onToggle: () -> Unit,
    onDelete: () -> Unit
) {
    val colors = AppTheme.colors
    val checkAnimation by animateFloatAsState(
        targetValue = if (todo.completed) 1f else 0f,
        animationSpec = spring(dampingRatio = 0.6f), label = "check"
    )

    Row(
        modifier = Modifier
            .fillMaxWidth()
            .clip(RoundedCornerShape(12.dp))
            .background(colors.card.copy(alpha = 0.5f))
            .clickable(onClick = onToggle)
            .padding(horizontal = 14.dp, vertical = 12.dp),
        verticalAlignment = Alignment.CenterVertically
    ) {
        // Checkbox Circle
        Box(
            modifier = Modifier
                .size(22.dp)
                .clip(CircleShape)
                .background(
                    if (todo.completed) colors.text else colors.bg,
                )
                .border(
                    width = 1.5.dp,
                    color = if (todo.completed) colors.text else colors.textMuted,
                    shape = CircleShape
                ),
            contentAlignment = Alignment.Center
        ) {
            if (todo.completed) {
                Text("✓", color = colors.bg, fontSize = 11.sp, fontWeight = FontWeight.Bold)
            }
        }

        Spacer(Modifier.width(12.dp))

        Column(modifier = Modifier.weight(1f)) {
            Text(
                todo.text,
                style = MaterialTheme.typography.bodyMedium,
                color = if (todo.completed) colors.textMuted else colors.text,
                textDecoration = if (todo.completed) TextDecoration.LineThrough else null,
                maxLines = 2,
                overflow = TextOverflow.Ellipsis
            )

            Row(
                modifier = Modifier.padding(top = 3.dp),
                horizontalArrangement = Arrangement.spacedBy(6.dp),
                verticalAlignment = Alignment.CenterVertically
            ) {
                // Category tag
                Box(
                    modifier = Modifier
                        .background(colors.input, RoundedCornerShape(10.dp))
                        .padding(horizontal = 8.dp, vertical = 2.dp)
                ) {
                    Text(
                        todo.category.label,
                        fontFamily = SpaceMono,
                        fontSize = 8.sp,
                        fontWeight = FontWeight.SemiBold,
                        color = colors.textSecondary,
                        letterSpacing = 0.5.sp
                    )
                }

                // Date
                todo.date?.let { date ->
                    Text(
                        date.format(DateTimeFormatter.ofPattern("dd. MMM")),
                        fontFamily = SpaceMono,
                        fontSize = 9.sp,
                        color = colors.textMuted
                    )
                }
            }
        }

        // Delete button
        Box(
            modifier = Modifier
                .size(28.dp)
                .clip(CircleShape)
                .clickable(onClick = onDelete),
            contentAlignment = Alignment.Center
        ) {
            Text("×", color = colors.textMuted, fontSize = 16.sp, fontFamily = SpaceMono)
        }
    }
}

package com.antiprocrastinator.app.ui.theme
import androidx.compose.ui.graphics.Color
// ── Light Theme ── val LightBg = Color(0xFFF2F2F2) val LightCard = Color(0xFFFFFFFF) val LightInput = Color(0xFFF7F7F7) val LightText = Color(0xFF0A0A0A) val LightTextSecondary = Color(0xFF555555) val LightTextMuted = Color(0xFF999999) val LightBorder = Color(0xFFE0E0E0) val LightAccent = Color(0xFF0A0A0A) val LightRed = Color(0xFFD42020)
// ── Dark Theme ── val DarkBg = Color(0xFF0A0A0A) val DarkCard = Color(0xFF141414) val DarkInput = Color(0xFF1A1A1A) val DarkText = Color(0xFFE8E8E8) val DarkTextSecondary = Color(0xFF888888) val DarkTextMuted = Color(0xFF555555) val DarkBorder = Color(0xFF252525) val DarkAccent = Color(0xFFE8E8E8) val DarkRed = Color(0xFFFF4444)
// ── Category Colors ── val CategoryArbeit = Color(0xFF1E3A5F) val CategoryPersoenlich = Color(0xFF2563EB) val CategoryGesundheit = Color(0xFF60A5FA) val CategoryLernen = Color(0xFFBFDBFE)
// ── Chart Colors ── val ChartGreen = Color(0xFF22A355) val ChartYellow = Color(0xFFD4A520)

package com.antiprocrastinator.app.ui.theme
import androidx.compose.foundation.isSystemInDarkTheme import androidx.compose.material3.* import androidx.compose.runtime.Composable import androidx.compose.runtime.CompositionLocalProvider import androidx.compose.runtime.staticCompositionLocalOf import androidx.compose.ui.graphics.Color import androidx.compose.ui.text.TextStyle import androidx.compose.ui.text.font.Font import androidx.compose.ui.text.font.FontFamily import androidx.compose.ui.text.font.FontWeight import androidx.compose.ui.unit.sp
// Wir verwenden system monospace als Fallback val SpaceMono = FontFamily.Monospace val SpaceGrotesk = FontFamily.SansSerif
// ══════════════════════════════════════════════════════════ // App-spezifische Farben (erweitert Material) // ══════════════════════════════════════════════════════════
data class AppColors( val bg: Color, val card: Color, val input: Color, val text: Color, val textSecondary: Color, val textMuted: Color, val border: Color, val accent: Color, val red: Color, val isDark: Boolean )
val LocalAppColors = staticCompositionLocalOf { AppColors( bg = LightBg, card = LightCard, input = LightInput, text = LightText, textSecondary = LightTextSecondary, textMuted = LightTextMuted, border = LightBorder, accent = LightAccent, red = LightRed, isDark = false ) }
val LightAppColors = AppColors( bg = LightBg, card = LightCard, input = LightInput, text = LightText, textSecondary = LightTextSecondary, textMuted = LightTextMuted, border = LightBorder, accent = LightAccent, red = LightRed, isDark = false )
val DarkAppColors = AppColors( bg = DarkBg, card = DarkCard, input = DarkInput, text = DarkText, textSecondary = DarkTextSecondary, textMuted = DarkTextMuted, border = DarkBorder, accent = DarkAccent, red = DarkRed, isDark = true )
// ══════════════════════════════════════════════════════════ // Typography // ══════════════════════════════════════════════════════════
val AppTypography = Typography( headlineLarge = TextStyle( fontFamily = SpaceMono, fontWeight = FontWeight.Bold, fontSize = 36.sp, letterSpacing = 2.sp ), headlineMedium = TextStyle( fontFamily = SpaceMono, fontWeight = FontWeight.Bold, fontSize = 24.sp, letterSpacing = 1.sp ), titleLarge = TextStyle( fontFamily = SpaceMono, fontWeight = FontWeight.SemiBold, fontSize = 16.sp, letterSpacing = 1.5.sp ), titleMedium = TextStyle( fontFamily = SpaceMono, fontWeight = FontWeight.SemiBold, fontSize = 13.sp, letterSpacing = 1.5.sp ), bodyLarge = TextStyle( fontFamily = SpaceGrotesk, fontWeight = FontWeight.Normal, fontSize = 14.sp ), bodyMedium = TextStyle( fontFamily = SpaceGrotesk, fontWeight = FontWeight.Normal, fontSize = 12.sp ), bodySmall = TextStyle( fontFamily = SpaceGrotesk, fontWeight = FontWeight.Normal, fontSize = 10.sp ), labelLarge = TextStyle( fontFamily = SpaceMono, fontWeight = FontWeight.Bold, fontSize = 10.sp, letterSpacing = 2.sp ), labelMedium = TextStyle( fontFamily = SpaceMono, fontWeight = FontWeight.SemiBold, fontSize = 9.sp, letterSpacing = 1.5.sp ), labelSmall = TextStyle( fontFamily = SpaceMono, fontWeight = FontWeight.SemiBold, fontSize = 8.sp, letterSpacing = 1.sp ) )
// ══════════════════════════════════════════════════════════ // Theme Composable // ══════════════════════════════════════════════════════════
@Composable fun AntiProcrastinatorTheme( darkTheme: Boolean = isSystemInDarkTheme(), content: @Composable () -> Unit ) { val appColors = if (darkTheme) DarkAppColors else LightAppColors
val colorScheme = if (darkTheme) { darkColorScheme( background = DarkBg, surface = DarkCard, onBackground = DarkText, onSurface = DarkText, primary = DarkAccent, onPrimary = DarkBg, error = DarkRed ) } else { lightColorScheme( background = LightBg, surface = LightCard, onBackground = LightText, onSurface = LightText, primary = LightAccent, onPrimary = LightBg, error = LightRed ) }
CompositionLocalProvider(LocalAppColors provides appColors) { MaterialTheme( colorScheme = colorScheme, typography = AppTypography, content = content ) } }
// Extension für einfachen Zugriff object AppTheme { val colors: AppColors @Composable get() = LocalAppColors.current }

