import SwiftUI

@main
struct AntiProcrastinatorApp: App {
    @StateObject private var appState = AppState()

    var body: some Scene {
        WindowGroup {
            ContentView()
                .environmentObject(appState)
                .preferredColorScheme(appState.isDarkMode ? .dark : .light)
        }
    }
}

class AppState: ObservableObject {
    @Published var isDarkMode: Bool {
        didSet { UserDefaults.standard.set(isDarkMode, forKey: "dark_mode") }
    }

    init() {
        self.isDarkMode = UserDefaults.standard.bool(forKey: "dark_mode")
    }
}

import SwiftUI

/// ContentView — Entry Point, zeigt die Swipe-Navigation
struct ContentView: View {
    @EnvironmentObject var appState: AppState

    var body: some View {
        SwipeNavigationView()
    }
}

import Foundation

// ══════════════════════════════════════════════════════════
// To-Do Model
// ══════════════════════════════════════════════════════════

struct Todo: Identifiable, Codable, Equatable {
    let id: String
    var text: String
    var date: Date?
    var category: TodoCategory
    var completed: Bool
    var createdAt: Date

    init(text: String, date: Date? = nil, category: TodoCategory = .arbeit) {
        self.id = UUID().uuidString
        self.text = text
        self.date = date
        self.category = category
        self.completed = false
        self.createdAt = Date()
    }
}

enum TodoCategory: String, Codable, CaseIterable {
    case arbeit = "arbeit"
    case persoenlich = "persoenlich"
    case gesundheit = "gesundheit"
    case lernen = "lernen"

    var label: String {
        switch self {
        case .arbeit: return "Arbeit"
        case .persoenlich: return "Persönlich"
        case .gesundheit: return "Gesundheit"
        case .lernen: return "Lernen"
        }
    }
}

enum TodoFilter: CaseIterable {
    case all, today, open, done

    var label: String {
        switch self {
        case .all: return "Alle"
        case .today: return "Heute"
        case .open: return "Offen"
        case .done: return "Erledigt"
        }
    }
}

struct TodoStats {
    var total: Int = 0
    var done: Int = 0
    var open: Int = 0
    var rate: Int = 0
    var todayCompleted: Int = 0
}

// ══════════════════════════════════════════════════════════
// Planer Models
// ══════════════════════════════════════════════════════════

enum PlanerMode: String, Codable, CaseIterable {
    case schule, bachelor, master, provadis

    var label: String {
        switch self {
        case .schule: return "Schulplaner"
        case .bachelor: return "Bachelor Studienplan"
        case .master: return "Master Studienplan"
        case .provadis: return "Studienplan Provadis"
        }
    }

    var periodLabel: String {
        switch self {
        case .schule: return "Klasse"
        default: return "Semester"
        }
    }

    var hasEcts: Bool { self != .schule }
    var isSchule: Bool { self == .schule }

    var icon: String {
        switch self {
        case .schule: return ".:S:."
        case .bachelor: return ".:B:."
        case .master: return ".:M:."
        case .provadis: return ".:P:."
        }
    }

    var desc: String {
        switch self {
        case .schule: return "Klassen 5–13"
        case .bachelor: return "6 Semester · 180 ECTS"
        case .master: return "4 Semester · 120 ECTS"
        case .provadis: return "Informatik B.Sc."
        }
    }
}

struct PlanerPeriod: Codable, Identifiable {
    var id = UUID().uuidString
    var period: Int
    var modules: [PlanerModule]
}

struct PlanerModule: Codable, Identifiable {
    var id: String = UUID().uuidString
    var name: String
    var prof: String = ""
    var points: Int = 5
    var pruefung: String = ""
    var isWab: Bool = false
    var noten: SchulNoten?
    var grade: Double?
    var status: ModuleStatus = .offen
}

struct SchulNoten: Codable {
    var schulaufgabe: [Int] = []
    var ex: [Int] = []
    var muendlich: [Int] = []
}

enum ModuleStatus: String, Codable {
    case offen, bestanden, nichtBestanden = "nicht_bestanden"

    var label: String {
        switch self {
        case .offen: return "Offen"
        case .bestanden: return "Bestanden"
        case .nichtBestanden: return "Nicht bestanden"
        }
    }
}

struct PlanerStats {
    var totalPoints: Int = 0
    var completedPoints: Int = 0
    var average: Double = 0.0
    var gradedPoints: Int = 0
}

// ══════════════════════════════════════════════════════════
// Weather Model
// ══════════════════════════════════════════════════════════

struct WeatherData: Codable {
    var temp: Int = 0
    var desc: String = ""
    var city: String = ""
    var dailyMax: [Int] = []
    var dailyMin: [Int] = []
    var dailyCodes: [Int] = []
    var dailyDates: [String] = []
}

// ══════════════════════════════════════════════════════════
// Chart Data
// ══════════════════════════════════════════════════════════

struct ChartData {
    var labels: [String]
    var values: [Int]
}

enum ChartRange: CaseIterable {
    case week, month, year
    var label: String {
        switch self {
        case .week: return "W"
        case .month: return "M"
        case .year: return "J"
        }
    }
}

// ══════════════════════════════════════════════════════════
// Daily Quotes
// ══════════════════════════════════════════════════════════

struct Quote {
    let text: String
    let author: String
}

struct Quotes {
    static let list: [Quote] = [
        Quote(text: "Der beste Zeitpunkt anzufangen war gestern. Der zweitbeste ist jetzt.", author: "Chinesisches Sprichwort"),
        Quote(text: "Es ist nicht wenig Zeit, die wir haben, sondern viel Zeit, die wir nicht nutzen.", author: "Seneca"),
        Quote(text: "Disziplin ist die Brücke zwischen Zielen und Ergebnissen.", author: "Jim Rohn"),
        Quote(text: "Du musst nicht großartig sein, um anzufangen. Aber du musst anfangen, um großartig zu werden.", author: "Zig Ziglar"),
        Quote(text: "Der einzige Weg, großartige Arbeit zu leisten, ist zu lieben, was man tut.", author: "Steve Jobs"),
        Quote(text: "Kleine Schritte sind besser als große Pläne.", author: "Unbekannt"),
        Quote(text: "Perfektion ist der Feind des Fortschritts.", author: "Winston Churchill"),
        Quote(text: "Erfolg ist die Summe kleiner Anstrengungen, Tag für Tag wiederholt.", author: "Robert Collier"),
        Quote(text: "Motivation bringt dich in Gang. Gewohnheit bringt dich ans Ziel.", author: "Jim Ryun"),
        Quote(text: "Mach es jetzt. Manchmal wird aus Später Nie.", author: "Unbekannt"),
        Quote(text: "Der Weg entsteht beim Gehen.", author: "Antonio Machado"),
        Quote(text: "Fortschritt, nicht Perfektion.", author: "Unbekannt"),
        Quote(text: "Jeder Experte war einmal ein Anfänger.", author: "Helen Hayes"),
        Quote(text: "Handle, bevor du bereit bist.", author: "Mel Robbins"),
    ]

    static func daily() -> Quote {
        let dayOfYear = Calendar.current.ordinality(of: .day, in: .year, for: Date()) ?? 1
        return list[dayOfYear % list.count]
    }
}

import SwiftUI

/// Snapchat-Style Cross-Navigation mit SwiftUI
///
///              [Overview]    (oben — Uhr, Wetter, Planer)
///                  ↑
/// [Summary] ← [To-Do] → [Calendar]
///                  ↓
///           [Visualizations]  (unten — Charts, Fortschritt)

struct SwipeNavigationView: View {
    @StateObject private var viewModel = TodoViewModel()
    @State private var horizontalPage: Int = 1    // 0=Summary, 1=ToDo, 2=Calendar
    @State private var verticalPage: Int = 0      // -1=Overview, 0=ToDo, 1=Visualizations
    @State private var dragOffset: CGSize = .zero
    @State private var isDragging = false

    var body: some View {
        GeometryReader { geo in
            let screenW = geo.size.width
            let screenH = geo.size.height

            ZStack {
                // Background
                Color(hex: "0A0A0A").ignoresSafeArea() // TODO: use theme

                // ── Current Page ──
                currentPage
                    .offset(x: dragOffset.width, y: dragOffset.height)

                // ── Peek Pages (during drag) ──

                // Left peek (Summary)
                if horizontalPage == 1 && verticalPage == 0 && dragOffset.width > 20 {
                    SummaryView(viewModel: viewModel)
                        .offset(x: -screenW + dragOffset.width)
                        .opacity(Double(min(dragOffset.width / screenW, 1)) * 0.9 + 0.1)
                        .transition(.move(edge: .leading))
                }

                // Right peek (Calendar)
                if horizontalPage == 1 && verticalPage == 0 && dragOffset.width < -20 {
                    CalendarView(viewModel: viewModel)
                        .offset(x: screenW + dragOffset.width)
                        .opacity(Double(min(-dragOffset.width / screenW, 1)) * 0.9 + 0.1)
                        .transition(.move(edge: .trailing))
                }

                // Top peek (Overview)
                if horizontalPage == 1 && verticalPage == 0 && dragOffset.height > 20 {
                    OverviewView(viewModel: viewModel)
                        .offset(y: -screenH + dragOffset.height)
                        .opacity(Double(min(dragOffset.height / screenH, 1)) * 0.9 + 0.1)
                }

                // Bottom peek (Visualizations)
                if horizontalPage == 1 && verticalPage == 0 && dragOffset.height < -20 {
                    VisualizationsView(viewModel: viewModel)
                        .offset(y: screenH + dragOffset.height)
                        .opacity(Double(min(-dragOffset.height / screenH, 1)) * 0.9 + 0.1)
                }

                // ── Page Indicators ──
                if horizontalPage == 1 && verticalPage == 0 {
                    VStack {
                        Spacer()

                        // Horizontal dots
                        HStack(spacing: 8) {
                            ForEach(0..<3) { i in
                                Circle()
                                    .fill(Color.white.opacity(i == 1 ? 0.8 : 0.3))
                                    .frame(width: i == 1 ? 8 : 5, height: i == 1 ? 8 : 5)
                            }
                        }
                        .padding(.bottom, 40)
                    }
                    .allowsHitTesting(false)

                    // Vertical dots
                    HStack {
                        Spacer()
                        VStack(spacing: 8) {
                            ForEach(-1..<2) { i in
                                Circle()
                                    .fill(Color.white.opacity(i == 0 ? 0.8 : 0.3))
                                    .frame(width: i == 0 ? 8 : 5, height: i == 0 ? 8 : 5)
                            }
                        }
                        .padding(.trailing, 12)
                    }
                    .allowsHitTesting(false)
                }
            }
            .gesture(
                DragGesture()
                    .onChanged { value in
                        isDragging = true
                        let translation = value.translation

                        // Allow dragging based on current page
                        if horizontalPage == 1 && verticalPage == 0 {
                            // On center — allow all directions with resistance at edges
                            dragOffset = translation
                        } else if horizontalPage == 0 {
                            // On Summary — only allow swipe left (to go back to center)
                            dragOffset = CGSize(width: min(0, translation.width) * 0.3 + max(0, translation.width), height: 0)
                        } else if horizontalPage == 2 {
                            // On Calendar — only allow swipe right (to go back)
                            dragOffset = CGSize(width: max(0, translation.width) * 0.3 + min(0, translation.width), height: 0)
                        } else if verticalPage == -1 {
                            dragOffset = CGSize(width: 0, height: min(0, translation.height) * 0.3 + max(0, translation.height))
                        } else if verticalPage == 1 {
                            dragOffset = CGSize(width: 0, height: max(0, translation.height) * 0.3 + min(0, translation.height))
                        }
                    }
                    .onEnded { value in
                        isDragging = false
                        let thresholdH = screenW * 0.25
                        let thresholdV = screenH * 0.2
                        let translation = value.translation

                        withAnimation(.spring(response: 0.4, dampingFraction: 0.8)) {
                            // Determine dominant axis
                            if abs(translation.width) > abs(translation.height) {
                                // Horizontal
                                if translation.width > thresholdH && horizontalPage > 0 {
                                    if horizontalPage == 1 { verticalPage = 0 }
                                    horizontalPage -= 1
                                    HapticManager.shared.swipeFeedback()
                                } else if translation.width < -thresholdH && horizontalPage < 2 {
                                    if horizontalPage == 1 { verticalPage = 0 }
                                    horizontalPage += 1
                                    HapticManager.shared.swipeFeedback()
                                }
                            } else {
                                // Vertical (nur auf center)
                                if horizontalPage == 1 {
                                    if translation.height > thresholdV && verticalPage > -1 {
                                        verticalPage -= 1
                                        horizontalPage = 1
                                        HapticManager.shared.swipeFeedback()
                                    } else if translation.height < -thresholdV && verticalPage < 1 {
                                        verticalPage += 1
                                        horizontalPage = 1
                                        HapticManager.shared.swipeFeedback()
                                    }
                                }
                            }
                            dragOffset = .zero
                        }
                    }
            )
            .animation(.spring(response: 0.3, dampingFraction: 0.85), value: dragOffset)
        }
        .ignoresSafeArea()
    }

    @ViewBuilder
    private var currentPage: some View {
        switch (horizontalPage, verticalPage) {
        case (0, _):
            SummaryView(viewModel: viewModel)
        case (2, _):
            CalendarView(viewModel: viewModel)
        case (1, -1):
            OverviewView(viewModel: viewModel)
        case (1, 1):
            VisualizationsView(viewModel: viewModel)
        default:
            TodoView(viewModel: viewModel)
        }
    }
}

import Foundation

/// StorageService — Persistenz mit UserDefaults + JSON Codable
class StorageService {
    static let shared = StorageService()
    private let defaults = UserDefaults.standard
    private let encoder = JSONEncoder()
    private let decoder = JSONDecoder()

    // ── Todos ──

    func getTodos() -> [Todo] {
        guard let data = defaults.data(forKey: "todos") else { return [] }
        return (try? decoder.decode([Todo].self, from: data)) ?? []
    }

    func saveTodos(_ todos: [Todo]) {
        if let data = try? encoder.encode(todos) {
            defaults.set(data, forKey: "todos")
        }
    }

    // ── Planer ──

    func getPlanerMode() -> PlanerMode? {
        guard let raw = defaults.string(forKey: "planer_mode") else { return nil }
        return PlanerMode(rawValue: raw)
    }

    func setPlanerMode(_ mode: PlanerMode?) {
        defaults.set(mode?.rawValue, forKey: "planer_mode")
    }

    func getPlanerData() -> [PlanerPeriod] {
        guard let data = defaults.data(forKey: "planer_data") else { return [] }
        return (try? decoder.decode([PlanerPeriod].self, from: data)) ?? []
    }

    func savePlanerData(_ data: [PlanerPeriod]) {
        if let encoded = try? encoder.encode(data) {
            defaults.set(encoded, forKey: "planer_data")
        }
    }

    // ── Weather Cache ──

    func getCachedWeather() -> WeatherData? {
        guard let data = defaults.data(forKey: "weather_cache") else { return nil }
        let time = defaults.double(forKey: "weather_cache_time")
        guard Date().timeIntervalSince1970 - time < 1800 else { return nil }
        return try? decoder.decode(WeatherData.self, from: data)
    }

    func cacheWeather(_ weather: WeatherData) {
        if let data = try? encoder.encode(weather) {
            defaults.set(data, forKey: "weather_cache")
            defaults.set(Date().timeIntervalSince1970, forKey: "weather_cache_time")
        }
    }

    // ── Today Completed Count (für Haptik-Intensität) ──

    func getTodayCompletedCount() -> Int {
        let savedDate = defaults.string(forKey: "haptic_date") ?? ""
        let today = Self.todayString()
        return savedDate == today ? defaults.integer(forKey: "haptic_count") : 0
    }

    func incrementTodayCompleted() {
        let today = Self.todayString()
        let savedDate = defaults.string(forKey: "haptic_date") ?? ""
        let count = savedDate == today ? defaults.integer(forKey: "haptic_count") : 0
        defaults.set(today, forKey: "haptic_date")
        defaults.set(count + 1, forKey: "haptic_count")
    }

    // ── Dark Mode ──

    var isDarkMode: Bool {
        get { defaults.bool(forKey: "dark_mode") }
        set { defaults.set(newValue, forKey: "dark_mode") }
    }

    // ── Helper ──

    static func todayString() -> String {
        let formatter = DateFormatter()
        formatter.dateFormat = "yyyy-MM-dd"
        formatter.timeZone = TimeZone(identifier: "Europe/Berlin")
        return formatter.string(from: Date())
    }
}

import Foundation
import CoreLocation

/// WeatherService — Holt Wetterdaten von Open-Meteo API
class WeatherService: NSObject, CLLocationManagerDelegate {
    static let shared = WeatherService()

    private let locationManager = CLLocationManager()
    private var completion: ((WeatherData?) -> Void)?

    private let wmoDescriptions: [Int: String] = [
        0: "Klar", 1: "Überwiegend klar", 2: "Teilweise bewölkt", 3: "Bedeckt",
        45: "Nebel", 48: "Nebel mit Reif",
        51: "Leichter Nieselregen", 53: "Nieselregen", 55: "Starker Nieselregen",
        61: "Leichter Regen", 63: "Regen", 65: "Starker Regen",
        71: "Leichter Schneefall", 73: "Schneefall", 75: "Starker Schneefall",
        80: "Regenschauer", 81: "Starke Regenschauer", 82: "Heftige Regenschauer",
        95: "Gewitter", 96: "Gewitter mit Hagel", 99: "Gewitter mit starkem Hagel"
    ]

    override init() {
        super.init()
        locationManager.delegate = self
    }

    func fetchWeather(completion: @escaping (WeatherData?) -> Void) {
        // Check cache first
        if let cached = StorageService.shared.getCachedWeather() {
            completion(cached)
            return
        }

        self.completion = completion
        locationManager.requestWhenInUseAuthorization()
        locationManager.requestLocation()
    }

    func locationManager(_ manager: CLLocationManager, didUpdateLocations locations: [CLLocation]) {
        guard let location = locations.first else { return }
        fetchFromAPI(lat: location.coordinate.latitude, lon: location.coordinate.longitude, city: "Mein Standort")
    }

    func locationManager(_ manager: CLLocationManager, didFailWithError error: Error) {
        // Fallback: Berlin
        fetchFromAPI(lat: 52.52, lon: 13.41, city: "Berlin")
    }

    private func fetchFromAPI(lat: Double, lon: Double, city: String) {
        let urlStr = "https://api.open-meteo.com/v1/forecast?latitude=\(lat)&longitude=\(lon)&current=temperature_2m,weather_code&daily=temperature_2m_max,temperature_2m_min,weather_code&forecast_days=7&timezone=Europe%2FBerlin"

        guard let url = URL(string: urlStr) else {
            completion?(nil)
            return
        }

        URLSession.shared.dataTask(with: url) { [weak self] data, _, error in
            guard let self = self, let data = data, error == nil else {
                DispatchQueue.main.async { self?.completion?(nil) }
                return
            }

            do {
                let json = try JSONSerialization.jsonObject(with: data) as? [String: Any]
                let current = json?["current"] as? [String: Any]
                let daily = json?["daily"] as? [String: Any]

                let temp = Int((current?["temperature_2m"] as? Double) ?? 0)
                let code = (current?["weather_code"] as? Int) ?? 0
                let desc = self.wmoDescriptions[code] ?? "Unbekannt"

                let dailyMax = (daily?["temperature_2m_max"] as? [Double])?.map { Int($0.rounded()) } ?? []
                let dailyMin = (daily?["temperature_2m_min"] as? [Double])?.map { Int($0.rounded()) } ?? []
                let dailyCodes = (daily?["weather_code"] as? [Int]) ?? []
                let dailyDates = (daily?["time"] as? [String]) ?? []

                let weather = WeatherData(
                    temp: temp, desc: desc, city: city,
                    dailyMax: dailyMax, dailyMin: dailyMin,
                    dailyCodes: dailyCodes, dailyDates: dailyDates
                )

                StorageService.shared.cacheWeather(weather)
                DispatchQueue.main.async { self.completion?(weather) }
            } catch {
                DispatchQueue.main.async { self.completion?(nil) }
            }
        }.resume()
    }
}

