// App Theme — Nothing Dot Design Style
// ══════════════════════════════════════════════════════════

struct AppTheme {
    // ── Light ──
    static let lightBg = Color(hex: "F2F2F2")
    static let lightCard = Color.white
    static let lightInput = Color(hex: "F7F7F7")
    static let lightText = Color(hex: "0A0A0A")
    static let lightTextSecondary = Color(hex: "555555")
    static let lightTextMuted = Color(hex: "999999")
    static let lightBorder = Color(hex: "E0E0E0")
    static let lightRed = Color(hex: "D42020")

    // ── Dark ──
    static let darkBg = Color(hex: "0A0A0A")
    static let darkCard = Color(hex: "141414")
    static let darkInput = Color(hex: "1A1A1A")
    static let darkText = Color(hex: "E8E8E8")
    static let darkTextSecondary = Color(hex: "888888")
    static let darkTextMuted = Color(hex: "555555")
    static let darkBorder = Color(hex: "252525")
    static let darkRed = Color(hex: "FF4444")
}

// Environment-based colors
struct ThemeColors {
    let bg: Color
    let card: Color
    let input: Color
    let text: Color
    let textSecondary: Color
    let textMuted: Color
    let border: Color
    let red: Color
    let isDark: Bool

    static let light = ThemeColors(
        bg: AppTheme.lightBg, card: AppTheme.lightCard, input: AppTheme.lightInput,
        text: AppTheme.lightText, textSecondary: AppTheme.lightTextSecondary,
        textMuted: AppTheme.lightTextMuted, border: AppTheme.lightBorder,
        red: AppTheme.lightRed, isDark: false
    )

    static let dark = ThemeColors(
        bg: AppTheme.darkBg, card: AppTheme.darkCard, input: AppTheme.darkInput,
        text: AppTheme.darkText, textSecondary: AppTheme.darkTextSecondary,
        textMuted: AppTheme.darkTextMuted, border: AppTheme.darkBorder,
        red: AppTheme.darkRed, isDark: true
    )
}

// Color from hex string
extension Color {
    init(hex: String) {
        let scanner = Scanner(string: hex.trimmingCharacters(in: CharacterSet.alphanumerics.inverted))
        var hexNumber: UInt64 = 0
        scanner.scanHexInt64(&hexNumber)
        let r = Double((hexNumber & 0xFF0000) >> 16) / 255
        let g = Double((hexNumber & 0x00FF00) >> 8) / 255
        let b = Double(hexNumber & 0x0000FF) / 255
        self.init(red: r, green: g, blue: b)
    }
}

// Environment key for theme
struct ThemeColorsKey: EnvironmentKey {
    static let defaultValue = ThemeColors.light
}

extension EnvironmentValues {
    var themeColors: ThemeColors {
        get { self[ThemeColorsKey.self] }
        set { self[ThemeColorsKey.self] = newValue }
    }
}

import UIKit

/// HapticManager — Kreatives haptisches Feedback mit Apple Taptic Engine
/// Je mehr To-Dos pro Tag abgehakt werden, desto stärker und kreativer die Vibration.
///
/// Stufe 1 (1-2 Tasks):   Leichtes Tick — UIImpactFeedbackGenerator(.light)
/// Stufe 2 (3-5 Tasks):   Mittlerer Impact — UIImpactFeedbackGenerator(.medium)
/// Stufe 3 (6-9 Tasks):   Schwerer Impact + Erfolgs-Notification
/// Stufe 4 (10+ Tasks):   Custom Triple-Tap Pattern — Belohnungs-Gefühl!

class HapticManager {
    static let shared = HapticManager()

    private let lightImpact = UIImpactFeedbackGenerator(style: .light)
    private let mediumImpact = UIImpactFeedbackGenerator(style: .medium)
    private let heavyImpact = UIImpactFeedbackGenerator(style: .heavy)
    private let rigidImpact = UIImpactFeedbackGenerator(style: .rigid)
    private let softImpact = UIImpactFeedbackGenerator(style: .soft)
    private let notification = UINotificationFeedbackGenerator()
    private let selection = UISelectionFeedbackGenerator()

    private init() {
        // Pre-prepare generators for faster response
        lightImpact.prepare()
        mediumImpact.prepare()
        heavyImpact.prepare()
    }

    /// Hauptmethode: Wird aufgerufen wenn ein ToDo abgehakt wird.
    /// todayCount = Anzahl der heute bereits abgehakten ToDos
    func todoChecked(todayCount: Int) {
        switch todayCount {
        case 0...2:
            lightTick()
        case 3...5:
            mediumTap()
        case 6...9:
            heavySuccess()
        default:
            celebrationBurst()
        }
    }

    // ── Stufe 1: Leichtes Tick ──
    private func lightTick() {
        selection.selectionChanged()
    }

    // ── Stufe 2: Mittlerer Tap ──
    private func mediumTap() {
        mediumImpact.impactOccurred(intensity: 0.7)
    }

    // ── Stufe 3: Schwerer Impact + Erfolgs-Notification ──
    private func heavySuccess() {
        heavyImpact.impactOccurred(intensity: 1.0)
        DispatchQueue.main.asyncAfter(deadline: .now() + 0.1) {
            self.notification.notificationOccurred(.success)
        }
    }

    // ── Stufe 4: Celebration Triple-Burst ──
    // Kreatives Pattern mit der Taptic Engine:
    // Schnelles Rigid-Soft-Rigid Pattern das sich wie "Applaus" anfühlt
    private func celebrationBurst() {
        // Burst 1: Rigid
        rigidImpact.impactOccurred(intensity: 0.8)

        // Burst 2: Heavy (nach kurzer Pause)
        DispatchQueue.main.asyncAfter(deadline: .now() + 0.08) {
            self.heavyImpact.impactOccurred(intensity: 1.0)
        }

        // Burst 3: Soft "Nachklingen"
        DispatchQueue.main.asyncAfter(deadline: .now() + 0.18) {
            self.softImpact.impactOccurred(intensity: 0.5)
        }

        // Burst 4: Finaler Success
        DispatchQueue.main.asyncAfter(deadline: .now() + 0.3) {
            self.notification.notificationOccurred(.success)
        }
    }

    // ── Utility Haptics ──

    func swipeFeedback() {
        softImpact.impactOccurred(intensity: 0.3)
    }

    func buttonPress() {
        lightImpact.impactOccurred(intensity: 0.5)
    }

    func error() {
        notification.notificationOccurred(.error)
    }

    func warning() {
        notification.notificationOccurred(.warning)
    }
}

import Foundation
import Combine

/// TodoViewModel — Verwaltet To-Do State und Business Logic
class TodoViewModel: ObservableObject {
    @Published var todos: [Todo] = []
    @Published var filter: TodoFilter = .all
    @Published var stats: TodoStats = TodoStats()
    @Published var categoryData: [TodoCategory: Int] = [:]

    private let storage = StorageService.shared

    init() {
        refresh()
    }

    func refresh() {
        let allTodos = storage.getTodos()

        // Apply filter
        switch filter {
        case .all:
            todos = allTodos
        case .today:
            let today = Calendar.current.startOfDay(for: Date())
            todos = allTodos.filter { todo in
                guard let date = todo.date else { return false }
                return Calendar.current.isDate(date, inSameDayAs: today)
            }
        case .open:
            todos = allTodos.filter { !$0.completed }
        case .done:
            todos = allTodos.filter { $0.completed }
        }

        todos.sort { a, b in
            if a.completed != b.completed { return !a.completed }
            return a.createdAt > b.createdAt
        }

        // Stats
        let total = allTodos.count
        let done = allTodos.filter { $0.completed }.count
        let open = total - done
        let rate = total > 0 ? (done * 100) / total : 0
        stats = TodoStats(total: total, done: done, open: open, rate: rate, todayCompleted: storage.getTodayCompletedCount())

        // Categories
        categoryData = Dictionary(grouping: allTodos, by: { $0.category }).mapValues { $0.count }
        for cat in TodoCategory.allCases {
            if categoryData[cat] == nil { categoryData[cat] = 0 }
        }
    }

    func addTodo(text: String, date: Date? = nil, category: TodoCategory = .arbeit) {
        guard !text.trimmingCharacters(in: .whitespaces).isEmpty else { return }
        var allTodos = storage.getTodos()
        allTodos.append(Todo(text: text, date: date ?? Date(), category: category))
        storage.saveTodos(allTodos)
        refresh()
    }

    func toggleTodo(_ id: String) {
        var allTodos = storage.getTodos()
        if let idx = allTodos.firstIndex(where: { $0.id == id }) {
            let wasDone = allTodos[idx].completed
            allTodos[idx].completed.toggle()
            storage.saveTodos(allTodos)
            if !wasDone {
                storage.incrementTodayCompleted()
                let count = storage.getTodayCompletedCount()
                HapticManager.shared.todoChecked(todayCount: count)
            }
        }
        refresh()
    }

    func deleteTodo(_ id: String) {
        var allTodos = storage.getTodos()
        allTodos.removeAll { $0.id == id }
        storage.saveTodos(allTodos)
        refresh()
    }

    func getChartData(range: ChartRange) -> ChartData {
        let allTodos = storage.getTodos()
        var labels: [String] = []
        var values: [Int] = []
        let calendar = Calendar.current

        switch range {
        case .week:
            for i in stride(from: 6, through: 0, by: -1) {
                let date = calendar.date(byAdding: .day, value: -i, to: Date())!
                let formatter = DateFormatter()
                formatter.locale = Locale(identifier: "de_DE")
                formatter.dateFormat = "EE"
                labels.append(formatter.string(from: date).uppercased())

                let dayTodos = allTodos.filter { todo in
                    guard let d = todo.date else { return false }
                    return calendar.isDate(d, inSameDayAs: date)
                }
                let completed = dayTodos.filter { $0.completed }.count
                let total = dayTodos.count
                values.append(total > 0 ? (completed * 100) / total : 0)
            }
        case .month:
            for i in stride(from: 29, through: 0, by: -1) {
                let date = calendar.date(byAdding: .day, value: -i, to: Date())!
                let formatter = DateFormatter()
                formatter.dateFormat = "dd.MM"
                labels.append(formatter.string(from: date))

                let dayTodos = allTodos.filter { todo in
                    guard let d = todo.date else { return false }
                    return calendar.isDate(d, inSameDayAs: date)
                }
                let completed = dayTodos.filter { $0.completed }.count
                let total = dayTodos.count
                values.append(total > 0 ? (completed * 100) / total : 0)
            }
        case .year:
            let months = ["Jan","Feb","Mär","Apr","Mai","Jun","Jul","Aug","Sep","Okt","Nov","Dez"]
            for i in stride(from: 11, through: 0, by: -1) {
                let date = calendar.date(byAdding: .month, value: -i, to: Date())!
                let month = calendar.component(.month, from: date)
                labels.append(months[month - 1])

                let monthTodos = allTodos.filter { todo in
                    guard let d = todo.date else { return false }
                    return calendar.component(.year, from: d) == calendar.component(.year, from: date) &&
                           calendar.component(.month, from: d) == month
                }
                let completed = monthTodos.filter { $0.completed }.count
                let total = monthTodos.count
                values.append(total > 0 ? (completed * 100) / total : 0)
            }
        }

        return ChartData(labels: labels, values: values)
    }

    func getTodayTodos() -> [Todo] {
        let allTodos = storage.getTodos()
        let today = Calendar.current.startOfDay(for: Date())
        return allTodos.filter { todo in
            guard let date = todo.date else { return false }
            return Calendar.current.isDate(date, inSameDayAs: today)
        }
    }

    func getTasksByDate() -> [Date: [Todo]] {
        return Dictionary(grouping: storage.getTodos().filter { $0.date != nil }, by: {
            Calendar.current.startOfDay(for: $0.date!)
        })
    }

    func getStreak() -> Int {
        let allTodos = storage.getTodos()
        var streak = 0
        var date = Calendar.current.startOfDay(for: Date())

        while true {
            let dayTodos = allTodos.filter { todo in
                guard let d = todo.date else { return false }
                return Calendar.current.isDate(d, inSameDayAs: date)
            }
            if dayTodos.isEmpty || !dayTodos.contains(where: { $0.completed }) { break }
            streak += 1
            date = Calendar.current.date(byAdding: .day, value: -1, to: date)!
        }
        return streak
    }
}

import SwiftUI
import EventKit

/// CalendarView — Fullscreen Kalender (Swipe nach links von ToDo)
/// Synchronisiert mit iOS Kalender (iCloud, Google Calendar etc.)
struct CalendarView: View {
    @ObservedObject var viewModel: TodoViewModel
    @State private var currentMonth = Date()
    @State private var selectedDate: Date? = nil
    @State private var systemEvents: [Date: [String]] = [:]

    private let colors = ThemeColors.dark
    private let calendar = Calendar.current
    private let dayNames = ["MO", "DI", "MI", "DO", "FR", "SA", "SO"]

    var body: some View {
        VStack(spacing: 0) {
            // ── Header ──
            Text("KALENDER")
                .font(.system(.caption, design: .monospaced))
                .fontWeight(.bold)
                .foregroundColor(colors.textMuted)
                .tracking(3)
                .frame(maxWidth: .infinity, alignment: .leading)
                .padding(.horizontal, 20)
                .padding(.top, 60)

            Spacer().frame(height: 16)

            // ── Month Navigation ──
            HStack {
                Button(action: { prevMonth() }) {
                    Circle()
                        .stroke(colors.border, lineWidth: 1)
                        .frame(width: 36, height: 36)
                        .overlay(Text("<").font(.system(size: 14, design: .monospaced)).foregroundColor(colors.textSecondary))
                }

                Spacer()

                Text(monthYearString())
                    .font(.system(size: 13, design: .monospaced))
                    .fontWeight(.bold)
                    .foregroundColor(colors.text)
                    .tracking(2)

                Spacer()

                Button(action: { nextMonth() }) {
                    Circle()
                        .stroke(colors.border, lineWidth: 1)
                        .frame(width: 36, height: 36)
                        .overlay(Text(">").font(.system(size: 14, design: .monospaced)).foregroundColor(colors.textSecondary))
                }
            }
            .padding(.horizontal, 20)

            Spacer().frame(height: 16)

            // ── Day Headers ──
            HStack(spacing: 0) {
                ForEach(dayNames, id: \.self) { day in
                    Text(day)
                        .font(.system(size: 9, design: .monospaced))
                        .fontWeight(.bold)
                        .foregroundColor(colors.textMuted)
                        .tracking(1)
                        .frame(maxWidth: .infinity)
                }
            }
            .padding(.horizontal, 16)

            Spacer().frame(height: 8)

            // ── Calendar Grid ──
            let days = generateDays()
            let rows = days.chunked(into: 7)

            VStack(spacing: 2) {
                ForEach(Array(rows.enumerated()), id: \.offset) { _, week in
                    HStack(spacing: 2) {
                        ForEach(Array(week.enumerated()), id: \.offset) { _, day in
                            CalendarDayCell(
                                day: day,
                                colors: colors,
                                tasksByDate: viewModel.getTasksByDate(),
                                systemEvents: systemEvents,
                                selectedDate: selectedDate,
                                onTap: {
                                    if let date = day.date {
                                        withAnimation(.spring(response: 0.3)) {
                                            selectedDate = selectedDate == date ? nil : date
                                        }
                                        HapticManager.shared.buttonPress()
                                    }
                                }
                            )
                        }
                    }
                }
            }
            .padding(.horizontal, 16)

            Spacer().frame(height: 12)

            // ── Selected Date Details ──
            if let date = selectedDate {
                let todos = viewModel.getTasksByDate()[calendar.startOfDay(for: date)] ?? []
                let events = systemEvents[calendar.startOfDay(for: date)] ?? []

                VStack(alignment: .leading, spacing: 8) {
                    Text(formatDate(date))
                        .font(.system(size: 10, design: .monospaced))
                        .fontWeight(.bold)
                        .foregroundColor(colors.textMuted)
                        .tracking(1)

                    if todos.isEmpty && events.isEmpty {
                        Text("Keine Termine")
                            .font(.system(size: 11, design: .monospaced))
                            .foregroundColor(colors.textMuted)
                    }

                    ForEach(events, id: \.self) { event in
                        HStack(spacing: 8) {
                            RoundedRectangle(cornerRadius: 2)
                                .fill(colors.red)
                                .frame(width: 3, height: 16)
                            Text(event)
                                .font(.system(size: 11))
                                .foregroundColor(colors.text)
                                .lineLimit(1)
                        }
                    }

                    ForEach(todos) { todo in
                        HStack(spacing: 8) {
                            RoundedRectangle(cornerRadius: 2)
                                .fill(colors.text.opacity(0.5))
                                .frame(width: 3, height: 16)
                            Text(todo.text)
                                .font(.system(size: 11))
                                .foregroundColor(todo.completed ? colors.textMuted : colors.text)
                                .strikethrough(todo.completed)
                                .lineLimit(1)
                        }
                    }
                }
                .padding(16)
                .frame(maxWidth: .infinity, alignment: .leading)
                .background(colors.card)
                .cornerRadius(16)
                .overlay(RoundedRectangle(cornerRadius: 16).stroke(colors.border, lineWidth: 1))
                .padding(.horizontal, 16)
                .transition(.move(edge: .bottom).combined(with: .opacity))
            }

            Spacer()

            // ── Sync Button ──
            Button(action: { requestCalendarAccess() }) {
                Text("SYNC MIT iOS KALENDER")
                    .font(.system(size: 9, design: .monospaced))
                    .fontWeight(.bold)
                    .foregroundColor(colors.textMuted)
                    .tracking(1)
                    .padding(.horizontal, 20)
                    .padding(.vertical, 10)
                    .overlay(RoundedRectangle(cornerRadius: 12).stroke(colors.border, lineWidth: 1))
            }
            .padding(.bottom, 40)
        }
        .background(colors.bg.ignoresSafeArea())
        .onAppear { requestCalendarAccess() }
    }

    // ── Calendar Logic ──

    private func monthYearString() -> String {
        let formatter = DateFormatter()
        formatter.locale = Locale(identifier: "de_DE")
        formatter.dateFormat = "MMMM yyyy"
        return formatter.string(from: currentMonth).uppercased()
    }

    private func prevMonth() {
        currentMonth = calendar.date(byAdding: .month, value: -1, to: currentMonth)!
    }

    private func nextMonth() {
        currentMonth = calendar.date(byAdding: .month, value: 1, to: currentMonth)!
    }

    private func generateDays() -> [CalendarDay] {
        var days: [CalendarDay] = []
        let components = calendar.dateComponents([.year, .month], from: currentMonth)
        let firstOfMonth = calendar.date(from: components)!
        let daysInMonth = calendar.range(of: .day, in: .month, for: currentMonth)!.count

        // Weekday offset (Mon=1)
        var startWeekday = calendar.component(.weekday, from: firstOfMonth) - 2
        if startWeekday < 0 { startWeekday = 6 }

        // Previous month padding
        let prevMonth = calendar.date(byAdding: .month, value: -1, to: firstOfMonth)!
        let daysInPrevMonth = calendar.range(of: .day, in: .month, for: prevMonth)!.count
        for i in stride(from: startWeekday - 1, through: 0, by: -1) {
            days.append(CalendarDay(number: daysInPrevMonth - i, isOtherMonth: true, date: nil))
        }

        // Current month
        for d in 1...daysInMonth {
            let date = calendar.date(from: DateComponents(year: components.year, month: components.month, day: d))
            let isToday = calendar.isDateInToday(date!)
            days.append(CalendarDay(number: d, isOtherMonth: false, date: date, isToday: isToday))
        }

        // Next month padding
        let remaining = (7 - (days.count % 7)) % 7
        for i in 1...max(remaining, 1) {
            if remaining == 0 { break }
            days.append(CalendarDay(number: i, isOtherMonth: true, date: nil))
        }

        return days
    }

    private func formatDate(_ date: Date) -> String {
        let formatter = DateFormatter()
        formatter.locale = Locale(identifier: "de_DE")
        formatter.dateFormat = "dd. MMMM yyyy"
        return formatter.string(from: date).uppercased()
    }

    // ── iOS Calendar Sync ──

    private func requestCalendarAccess() {
        let store = EKEventStore()
        if #available(iOS 17.0, *) {
            store.requestFullAccessToEvents { granted, _ in
                if granted { loadSystemEvents(store: store) }
            }
        } else {
            store.requestAccess(to: .event) { granted, _ in
                if granted { loadSystemEvents(store: store) }
            }
        }
    }

    private func loadSystemEvents(store: EKEventStore) {
        let start = calendar.date(byAdding: .month, value: -1, to: Date())!
        let end = calendar.date(byAdding: .month, value: 3, to: Date())!
        let predicate = store.predicateForEvents(withStart: start, end: end, calendars: nil)
        let events = store.events(matching: predicate)

        var result: [Date: [String]] = [:]
        for event in events {
            let day = calendar.startOfDay(for: event.startDate)
            result[day, default: []].append(event.title ?? "Termin")
        }

        DispatchQueue.main.async {
            systemEvents = result
        }
    }
}

struct CalendarDay {
    let number: Int
    let isOtherMonth: Bool
    var date: Date? = nil
    var isToday: Bool = false
}

struct CalendarDayCell: View {
    let day: CalendarDay
    let colors: ThemeColors
    let tasksByDate: [Date: [Todo]]
    let systemEvents: [Date: [String]]
    let selectedDate: Date?
    let onTap: () -> Void

    private let calendar = Calendar.current

    var body: some View {
        let isSelected = day.date != nil && selectedDate != nil && calendar.isDate(day.date!, inSameDayAs: selectedDate!)
        let hasTasks = day.date != nil && tasksByDate[calendar.startOfDay(for: day.date!)] != nil
        let hasEvents = day.date != nil && systemEvents[calendar.startOfDay(for: day.date!)] != nil

        Button(action: onTap) {
            VStack(spacing: 2) {
                Text("\(day.number)")
                    .font(.system(size: 12, design: .monospaced))
                    .fontWeight(day.isToday || isSelected ? .bold : .regular)
                    .foregroundColor(
                        isSelected ? colors.bg :
                        day.isOtherMonth ? colors.textMuted.opacity(0.35) :
                        colors.text
                    )

                if hasTasks || hasEvents {
                    HStack(spacing: 2) {
                        if hasTasks {
                            Circle()
                                .fill(isSelected ? colors.bg.opacity(0.7) : colors.text)
                                .frame(width: 4, height: 4)
                        }
                        if hasEvents {
                            Circle()
                                .fill(isSelected ? colors.bg.opacity(0.7) : colors.red)
                                .frame(width: 4, height: 4)
                        }
                    }
                }
            }
            .frame(maxWidth: .infinity)
            .aspectRatio(1, contentMode: .fit)
            .background(
                RoundedRectangle(cornerRadius: 12)
                    .fill(isSelected ? colors.red : day.isToday ? colors.text.opacity(0.08) : Color.clear)
            )
            .overlay(
                day.isToday && !isSelected ?
                    RoundedRectangle(cornerRadius: 12).stroke(colors.text, lineWidth: 1.5) : nil
            )
        }
        .disabled(day.isOtherMonth)
    }
}

// Helper extension
extension Array {
    func chunked(into size: Int) -> [[Element]] {
        stride(from: 0, to: count, by: size).map {
            Array(self[$0..<Swift.min($0 + size, count)])
        }
    }
}

import SwiftUI

/// OverviewView — Oben (Swipe nach unten von ToDo)
/// Pixel-Design Uhr, Wetter, Planer (Uni/Schule/Bachelor/Master/Provadis)
struct OverviewView: View {
    @ObservedObject var viewModel: TodoViewModel
    @State private var currentTime = Date()
    @State private var weather: WeatherData? = StorageService.shared.getCachedWeather()
    @State private var planerMode: PlanerMode? = StorageService.shared.getPlanerMode()
    @State private var planerData: [PlanerPeriod] = StorageService.shared.getPlanerData()

    private let colors = ThemeColors.dark
    private let timer = Timer.publish(every: 1, on: .main, in: .common).autoconnect()

    var body: some View {
        ScrollView {
            VStack(spacing: 16) {
                Text("ÜBERSICHT")
                    .font(.system(.caption, design: .monospaced))
                    .fontWeight(.bold)
                    .foregroundColor(colors.textMuted)
                    .tracking(3)
                    .padding(.top, 60)

                // ══════════════════════════════════════
                // Pixel Clock — Dot-Matrix Stil
                // ══════════════════════════════════════
                VStack(spacing: 12) {
                    // Analog Pixel Clock
                    Canvas { context, size in
                        drawPixelClock(context: context, size: size, time: currentTime)
                    }
                    .frame(width: 140, height: 140)

                    // Digital Display
                    let formatter = DateFormatter()
                    Text({
                        formatter.dateFormat = "HH:mm:ss"
                        formatter.timeZone = TimeZone(identifier: "Europe/Berlin")
                        return formatter.string(from: currentTime)
                    }())
                    .font(.system(size: 28, design: .monospaced))
                    .fontWeight(.light)
                    .foregroundColor(colors.text)
                    .tracking(2)

                    Text({
                        formatter.locale = Locale(identifier: "de_DE")
                        formatter.dateFormat = "EEEE, dd. MMMM yyyy"
                        return formatter.string(from: currentTime).uppercased()
                    }())
                    .font(.system(size: 9, design: .monospaced))
                    .foregroundColor(colors.textMuted)
                    .tracking(1)
                }
                .padding(24)
                .frame(maxWidth: .infinity)
                .background(colors.card)
                .cornerRadius(20)
                .overlay(RoundedRectangle(cornerRadius: 20).stroke(colors.border, lineWidth: 1))
                .onReceive(timer) { _ in currentTime = Date() }

                // ══════════════════════════════════════
                // Weather
                // ══════════════════════════════════════
